    /**
     * 自主饱和度 ≥ {@link #autonomySaturationThreshold()} 且用户未强制 {@code forceAuxLlm=true} 时，跳过本地模型辅助链，主位仅靠结构+圆/梦/人物草图合成。
     * <p>JVM 覆盖：{@code -Dlovingai.autonomy.saturation.threshold=0.99} 接近关闭该省略（仍受 baseUrl、超时等约束）。
     */
    private static double autonomySaturationThreshold() {
        String p = System.getProperty("lovingai.autonomy.saturation.threshold", "").trim();
        if (!p.isEmpty()) {
            try {
                double v = Double.parseDouble(p);
                if (Double.isNaN(v) || Double.isInfinite(v)) {
                    return 0.78;
                }
                return Math.max(0.5, Math.min(1.0, v));
            } catch (NumberFormatException ignored) {
                // fall through to default
            }
        }
        return 0.78;
    }

