    private static final String AUX_MARK_ASK_USER_LEGACY = "【向你追问】";
    private static final String AUX_MARK_ASK_MODEL = "【再向本机模型】";

    private static int indexOfAuxUserMarker(String t) {
        int i = t.indexOf(AUX_MARK_ASK_USER);
        if (i >= 0) {
            return i;
        }
        return t.indexOf(AUX_MARK_ASK_USER_LEGACY);
    }

    private static int auxUserMarkerLengthAt(String t, int iu) {
        if (iu < 0) {
            return AUX_MARK_ASK_USER.length();
        }
        if (t.regionMatches(iu, AUX_MARK_ASK_USER, 0, AUX_MARK_ASK_USER.length())) {
            return AUX_MARK_ASK_USER.length();
        }
        if (t.regionMatches(iu, AUX_MARK_ASK_USER_LEGACY, 0, AUX_MARK_ASK_USER_LEGACY.length())) {
            return AUX_MARK_ASK_USER_LEGACY.length();
        }
        return AUX_MARK_ASK_USER.length();
    }

