    /**
     * 与并联路径里 {@link OllamaProxy#generate} 的秒参数一致；{@link java.util.concurrent.CompletableFuture#get}
     * 不得更短，否则本地 GPU 易误判超时。
     */
    private static final int AUX_LLM_HTTP_TIMEOUT_ROUND1 =
            resolveLocalAiHttpTimeoutSec("lovingai.localai.httpTimeoutRound1Sec", 1200);
    private static final int AUX_LLM_HTTP_TIMEOUT_ROUND2 =
            resolveLocalAiHttpTimeoutSec("lovingai.localai.httpTimeoutRound2Sec", 900);
    private static final int AUX_LLM_HTTP_TIMEOUT_ROUND3 =
            resolveLocalAiHttpTimeoutSec("lovingai.localai.httpTimeoutRound3Sec", 900);
    /** 本机模型同模型重试次数（不降级）：默认 1 次，可用 -Dlovingai.localai.retryTimes 覆盖。 */
    private static final int LOCAL_AI_RETRY_TIMES = resolveLocalAiRetryTimes();
    /** 本机模型重试前等待毫秒：默认 900ms，可用 -Dlovingai.localai.retryDelayMs 覆盖。 */
    private static final int LOCAL_AI_RETRY_DELAY_MS = resolveLocalAiRetryDelayMs();
    private static final int LOCAL_AI_PROGRESS_LOG_SEC = resolveLocalAiProgressLogSec();
    private static final ScheduledExecutorService LOCAL_AI_PROGRESS_EXECUTOR =
            Executors.newSingleThreadScheduledExecutor(
                    r -> {
                        Thread t = new Thread(r, "LovingAI-localai-progress");
                        t.setDaemon(true);
                        return t;
                    });
    /** 主声先答后补发并联回声（默认开启）：-Dlovingai.dialogue.asyncAuxContinuation=false 可关闭。 */
    private static final boolean ASYNC_AUX_CONTINUATION_ENABLED =
            !"false"
                    .equalsIgnoreCase(
                            System.getProperty("lovingai.dialogue.asyncAuxContinuation", "true").trim());

    /**
     * 并联对话时，多路辅助生成可同时对本机 OpenAI 兼容服务发起请求；线程数可用系统属性 {@code
     * lovingai.auxLlm.threads} 覆盖（默认约 CPU×2，上限 32、下限 2）。
     */
    private static final int AUX_LLM_POOL_SIZE = resolveAuxLlmPoolSize();

    private static int resolveAuxLlmPoolSize() {
        String p = System.getProperty("lovingai.auxLlm.threads");
        if (p != null && !p.isBlank()) {
            try {
                int n = Integer.parseInt(p.trim());
                return Math.max(2, Math.min(64, n));
            } catch (NumberFormatException ignored) {
                // fall through
            }
        }
        int cores = Math.max(1, Runtime.getRuntime().availableProcessors());
        return Math.max(4, Math.min(32, cores * 2));
    }

    private static int resolveLocalAiRetryTimes() {
        String p = System.getProperty("lovingai.localai.retryTimes", "").trim();
        if (!p.isEmpty()) {
            try {
                return Math.max(0, Math.min(12, Integer.parseInt(p)));
            } catch (NumberFormatException ignored) {
                // fall through
            }
        }
        return 2;
    }

    private static int resolveLocalAiRetryDelayMs() {
        String p = System.getProperty("lovingai.localai.retryDelayMs", "").trim();
        if (!p.isEmpty()) {
            try {
                return Math.max(0, Math.min(10_000, Integer.parseInt(p)));
            } catch (NumberFormatException ignored) {
                // fall through
            }
        }
        return 1200;
    }

    private static int resolveLocalAiProgressLogSec() {
        String p = System.getProperty("lovingai.localai.progressLogSec", "").trim();
        if (!p.isEmpty()) {
            try {
                return Math.max(0, Math.min(60, Integer.parseInt(p)));
            } catch (NumberFormatException ignored) {
                // fall through
            }
        }
        return 12;
    }

    private static int resolveLocalAiHttpTimeoutSec(String key, int def) {
        String p = System.getProperty(key, "").trim();
        if (!p.isEmpty()) {
            try {
                return Math.max(30, Math.min(7200, Integer.parseInt(p)));
            } catch (NumberFormatException ignored) {
                // fall through
            }
        }
        return def;
    }

    private static String generateWithRetryNoDowngrade(
            String baseUrl, String model, String prompt, int timeoutSec, String stageTag) throws Exception {
        int promptChars = prompt == null ? 0 : prompt.length();
        long totalStart = System.currentTimeMillis();
        CognitionLog.append(
                "本地AI",
                "调用开始 stage="
                        + stageTag
                        + " model="
                        + model
                        + " timeoutSec="
                        + timeoutSec
                        + " promptChars="
                        + promptChars);
        Exception last = null;
        for (int attempt = 0; attempt <= LOCAL_AI_RETRY_TIMES; attempt++) {
            long attemptStart = System.currentTimeMillis();
            ScheduledFuture<?> ticker = null;
            if (LOCAL_AI_PROGRESS_LOG_SEC > 0) {
                int idx = attempt + 1;
                int total = LOCAL_AI_RETRY_TIMES + 1;
                ticker =
                        LOCAL_AI_PROGRESS_EXECUTOR.scheduleAtFixedRate(
                                () -> {
                                    long now = System.currentTimeMillis();
                                    long elAttemptSec = Math.max(0L, (now - attemptStart) / 1000L);
                                    long elTotalSec = Math.max(0L, (now - totalStart) / 1000L);
                                    CognitionLog.append(
                                            "本地AI",
                                            "推理中 stage="
                                                    + stageTag
                                                    + " attempt="
                                                    + idx
                                                    + "/"
                                                    + total
                                                    + " waited="
                                                    + elAttemptSec
                                                    + "s"
                                                    + " total="
                                                    + elTotalSec
                                                    + "s"
                                                    + " model="
                                                    + model
                                                    + " promptChars="
                                                    + promptChars);
                                },
                                LOCAL_AI_PROGRESS_LOG_SEC,
                                LOCAL_AI_PROGRESS_LOG_SEC,
                                TimeUnit.SECONDS);
            }
            try {
                String out =
                        OllamaProxy.generate(
                                baseUrl,
                                model,
                                prompt,
                                timeoutSec,
                                LocalAiPrefs.getOllamaGenerateOptionsJson());
                if (ticker != null) {
                    ticker.cancel(false);
                }
                long now = System.currentTimeMillis();
                CognitionLog.append(
                        "本地AI",
                        "调用完成 stage="
                                + stageTag
                                + " attempt="
                                + (attempt + 1)
                                + "/"
                                + (LOCAL_AI_RETRY_TIMES + 1)
                                + " tookMs="
                                + Math.max(0L, now - attemptStart)
                                + " totalMs="
                                + Math.max(0L, now - totalStart)
                                + " outChars="
                                + (out == null ? 0 : out.length()));
                return out;
            } catch (Exception e) {
                if (ticker != null) {
                    ticker.cancel(false);
                }
                last = e;
                boolean timeoutLike = isTimeoutLikeException(e);
                if (!timeoutLike || attempt >= LOCAL_AI_RETRY_TIMES) {
                    long now = System.currentTimeMillis();
                    CognitionLog.append(
                            "本地AI",
                            "调用失败 stage="
                                    + stageTag
                                    + " attempt="
                                    + (attempt + 1)
                                    + "/"
                                    + (LOCAL_AI_RETRY_TIMES + 1)
                                    + " tookMs="
                                    + Math.max(0L, now - attemptStart)
                                    + " totalMs="
                                    + Math.max(0L, now - totalStart)
                                    + " err="
                                    + (e.getMessage() == null
                                            ? e.getClass().getSimpleName()
                                            : e.getMessage()));
                    throw e;
                }
                CognitionLog.append(
                        "本地AI",
                        "同模型重试 stage="
                                + stageTag
                                + " attempt="
                                + (attempt + 1)
                                + "/"
                                + (LOCAL_AI_RETRY_TIMES + 1)
                                + " reason="
                                + (e.getMessage() == null ? e.getClass().getSimpleName() : e.getMessage()));
                if (LOCAL_AI_RETRY_DELAY_MS > 0) {
                    try {
                        Thread.sleep(LOCAL_AI_RETRY_DELAY_MS);
                    } catch (InterruptedException ie) {
                        Thread.currentThread().interrupt();
                        throw ie;
                    }
                }
            }
        }
        if (last != null) throw last;
        return "";
    }

    private static boolean isTimeoutLikeException(Throwable t) {
        Throwable cur = t;
        while (cur != null) {
            String m = cur.getMessage();
            if (m != null) {
                String s = m.toLowerCase(Locale.ROOT);
                if (s.contains("timeout")
                        || s.contains("timed out")
                        || s.contains("request timed out")
                        || s.contains("read timed out")) {
                    return true;
                }
            }
            cur = cur.getCause();
        }
        return t instanceof TimeoutException;
    }

    private static String localAiLatencyProfile() {
        return LocalAiPrefs.getLatencyProfile();
    }

    private static long auxRound1TimeoutByProfileSec() {
        return switch (localAiLatencyProfile()) {
            case "fast" -> AUX_LLM_ROUND1_TIMEOUT_SEC_FAST;
            case "deep" -> AUX_LLM_ROUND1_TIMEOUT_SEC_DEEP;
            default -> AUX_LLM_ROUND1_TIMEOUT_SEC_BALANCED;
        };
    }

    private static long auxRound2TimeoutByProfileSec() {
        return switch (localAiLatencyProfile()) {
            case "fast" -> AUX_LLM_ROUND2_TIMEOUT_SEC_FAST;
            case "deep" -> AUX_LLM_ROUND2_TIMEOUT_SEC_DEEP;
            default -> AUX_LLM_ROUND2_TIMEOUT_SEC_BALANCED;
        };
    }

    private static long auxRound3TimeoutByProfileSec() {
        return switch (localAiLatencyProfile()) {
            case "fast" -> AUX_LLM_ROUND3_TIMEOUT_SEC_FAST;
            case "deep" -> AUX_LLM_ROUND3_TIMEOUT_SEC_DEEP;
            default -> AUX_LLM_ROUND3_TIMEOUT_SEC_BALANCED;
        };
    }

    /** 并联辅助首轮：等待时间须覆盖 {@link #AUX_LLM_HTTP_TIMEOUT_ROUND1} 秒级 HTTP 请求。 */
    private static long auxFutureWaitSecRound1(boolean longInput, int crashLevel) {
        long http = AUX_LLM_HTTP_TIMEOUT_ROUND1 + (longInput ? LONG_INPUT_EXTRA_TIMEOUT_SEC : 0L);
        long legacy =
                Math.max(22L, auxRound1TimeoutByProfileSec() - (long) crashLevel * 8L)
                        + (longInput ? LONG_INPUT_EXTRA_TIMEOUT_SEC : 0L);
        return Math.max(http, legacy);
    }

    private static long auxFutureWaitSecRound2(boolean longInput, int crashLevel) {
        long extra = longInput ? LONG_INPUT_EXTRA_TIMEOUT_SEC / 2 : 0L;
        long http = AUX_LLM_HTTP_TIMEOUT_ROUND2 + extra;
        long legacy = Math.max(14L, auxRound2TimeoutByProfileSec() - (long) crashLevel * 6L) + extra;
        return Math.max(http, legacy);
    }

    private static long auxFutureWaitSecRound3(boolean longInput, int crashLevel) {
        long extra = longInput ? LONG_INPUT_EXTRA_TIMEOUT_SEC / 2 : 0L;
        long http = AUX_LLM_HTTP_TIMEOUT_ROUND3 + extra;
        long legacy = Math.max(10L, auxRound3TimeoutByProfileSec() - (long) crashLevel * 5L) + extra;
        return Math.max(http, legacy);
    }

    private static int defaultGenerateTimeoutSecByProfile() {
        return switch (localAiLatencyProfile()) {
            case "fast" -> 180;
            case "deep" -> 360;
            default -> 240;
        };
    }

    private static boolean localLlmCooldownActive(long nowMs) {
        return nowMs < LOCAL_LLM_COOLDOWN_UNTIL_MS;
    }

    private static void noteLocalLlmConnectFailure(String base, String detail) {
        int fails = Math.min(12, LOCAL_LLM_CONSECUTIVE_CONNECT_FAILS + 1);
        LOCAL_LLM_CONSECUTIVE_CONNECT_FAILS = fails;
        long now = System.currentTimeMillis();
        if (fails >= 2) {
            long cooldownMs = Math.min(120_000L, 20_000L + (long) (fails - 2) * 15_000L);
            LOCAL_LLM_COOLDOWN_UNTIL_MS = Math.max(LOCAL_LLM_COOLDOWN_UNTIL_MS, now + cooldownMs);
            CognitionLog.append(
                    "本地AI",
                    "连接失败熔断开启 base="
                            + base
                            + " fails="
                            + fails
                            + " cooldownMs="
                            + cooldownMs
                            + " detail="
                            + shortAnchor(detail, 140));
        } else {
            CognitionLog.append(
                    "本地AI",
                    "连接失败计数 base="
                            + base
                            + " fails="
                            + fails
                            + " detail="
                            + shortAnchor(detail, 140));
        }
    }

    private static void noteLocalLlmConnectSuccess() {
        if (LOCAL_LLM_CONSECUTIVE_CONNECT_FAILS > 0 || LOCAL_LLM_COOLDOWN_UNTIL_MS > 0L) {
            CognitionLog.append(
                    "本地AI",
                    "连接恢复成功，清零熔断 fails="
                            + LOCAL_LLM_CONSECUTIVE_CONNECT_FAILS
                            + " cooldownUntilMs="
                            + LOCAL_LLM_COOLDOWN_UNTIL_MS);
        }
        LOCAL_LLM_CONSECUTIVE_CONNECT_FAILS = 0;
        LOCAL_LLM_COOLDOWN_UNTIL_MS = 0L;
    }

    private static boolean localLlmReachableNow(String base, long nowMs) {
        if (base == null || base.isBlank()) {
            return false;
        }
        if (localLlmCooldownActive(nowMs)) {
            return false;
        }
        long probeFreshMs = 15_000L;
        if (LOCAL_LLM_LAST_PROBE_OK && nowMs - LOCAL_LLM_LAST_PROBE_MS <= probeFreshMs) {
            return true;
        }
        boolean ok = OllamaProxy.probeOpenAiV1Models(base);
        LOCAL_LLM_LAST_PROBE_MS = nowMs;
        LOCAL_LLM_LAST_PROBE_OK = ok;
        if (ok) {
            noteLocalLlmConnectSuccess();
            return true;
        }
        noteLocalLlmConnectFailure(base, "probe /v1/models unreachable");
        return false;
    }

    private static long resolveProactiveSelfThinkTimeoutMs() {
        String p = System.getProperty("lovingai.proactive.selfSolveTimeoutSec");
        if (p != null && !p.isBlank()) {
            try {
                long sec = Long.parseLong(p.trim());
                sec = Math.max(20L, Math.min(900L, sec));
                return sec * 1000L;
            } catch (NumberFormatException ignored) {
                // fall through
            }
        }
        return 95_000L;
    }

    private static boolean resolveDialogueAppendQuestion() {
        String p = System.getProperty("lovingai.dialogue.appendQuestion", "").trim();
        if (p.isEmpty()) {
            return true;
        }
        return truthyOrDefault(p, true);
    }

    /**
     * 是否在用户未回应挂起问句时自动推送「自解」文案。默认关闭：完整思考与回应走主对话 /api/chat，避免与主动通道抢戏。
     * 显式开启：{@code -Dlovingai.proactive.selfSolve=true}
     */
    private static boolean resolveProactiveSelfSolveEnabled() {
        String p = System.getProperty("lovingai.proactive.selfSolve");
        if (p == null || p.isBlank()) {
            return false;
        }
        String s = p.trim();
        return s.equalsIgnoreCase("true") || "1".equals(s) || s.equalsIgnoreCase("yes");
    }

