            server.createContext(
                    "/api/perception/config",
                    exchange -> {
                        try {
                            if (!checkAuth(exchange)) return;
                            String method = exchange.getRequestMethod();
                            if ("GET".equalsIgnoreCase(method)) {
                                sendJson(exchange, 200, buildPerceptionConfigJson());
                                return;
                            }
                            if (!"POST".equalsIgnoreCase(method)) {
                                exchange.sendResponseHeaders(405, -1);
                                exchange.close();
                                return;
                            }
                            Map<String, String> m = parseQuery(readRequestBodySmall(exchange));
                            if (m.containsKey("enabled")) {
                                PERCEPTION_ENABLED = truthyOrDefault(m.get("enabled"), PERCEPTION_ENABLED);
                            }
                            if (m.containsKey("networkUnlocked")) {
                                PERCEPTION_NETWORK_UNLOCKED =
                                        truthyOrDefault(
                                                m.get("networkUnlocked"),
                                                PERCEPTION_NETWORK_UNLOCKED);
                                if (PERCEPTION_NETWORK_UNLOCKED) {
                                    PERCEPTION_NETWORK_UNLOCK_UNTIL_MS =
                                            System.currentTimeMillis()
                                                    + Math.max(30, PERCEPTION_UNLOCK_WINDOW_SEC) * 1000L;
                                } else {
                                    PERCEPTION_NETWORK_UNLOCK_UNTIL_MS = 0L;
                                }
                            }
                            if (m.containsKey("unlockWindowSec")) {
                                PERCEPTION_UNLOCK_WINDOW_SEC =
                                        clampInt(
                                                parseIntOr(
                                                        PERCEPTION_UNLOCK_WINDOW_SEC,
                                                        m.get("unlockWindowSec")),
                                                30,
                                                3600);
                                if (PERCEPTION_NETWORK_UNLOCKED) {
                                    PERCEPTION_NETWORK_UNLOCK_UNTIL_MS =
                                            System.currentTimeMillis()
                                                    + PERCEPTION_UNLOCK_WINDOW_SEC * 1000L;
                                }
                            }
                            if (m.containsKey("intervalSec")) {
                                PERCEPTION_INTERVAL_SEC = clampInt(parseIntOr(PERCEPTION_INTERVAL_SEC, m.get("intervalSec")), 20, 3600);
                            }
                            if (m.containsKey("maxItems")) {
                                PERCEPTION_MAX_ITEMS_PER_RUN = clampInt(parseIntOr(PERCEPTION_MAX_ITEMS_PER_RUN, m.get("maxItems")), 1, 32);
                            }
                            if (m.containsKey("maxVideoFrames")) {
                                PERCEPTION_MAX_VIDEO_FRAMES = clampInt(parseIntOr(PERCEPTION_MAX_VIDEO_FRAMES, m.get("maxVideoFrames")), 1, 12);
                            }
                            if (m.containsKey("mode")) {
                                PERCEPTION_MODE = normalizePerceptionMode(m.get("mode"));
                            }
                            if (m.containsKey("filterAsciiHeavy")) {
                                PERCEPTION_FILTER_ASCII_HEAVY =
                                        truthyOrDefault(m.get("filterAsciiHeavy"), PERCEPTION_FILTER_ASCII_HEAVY);
                            }
                            if (m.containsKey("maxAsciiRatio")) {
                                double r = parseDoubleOr(PERCEPTION_MAX_ASCII_RATIO, m.get("maxAsciiRatio"));
                                PERCEPTION_MAX_ASCII_RATIO = Math.max(0.0, Math.min(1.0, r));
                            }
                            if (m.containsKey("blockSourcecodePrompt")) {
                                PERCEPTION_BLOCK_SOURCECODE_PROMPT =
                                        truthyOrDefault(
                                                m.get("blockSourcecodePrompt"),
                                                PERCEPTION_BLOCK_SOURCECODE_PROMPT);
                            }
                            persistPerceptionState();
                            sendJson(exchange, 200, buildPerceptionConfigJson());
                        } catch (Exception e) {
                            sendJson(
                                    exchange,
                                    500,
                                    "{\"error\":\""
                                            + SimplifiedJsonParser.escapeJson(e.getMessage())
                                            + "\"}");
                        }
                    });
