            dialogueTurnOrdinal = allocNextDialogueTurnOrdinal(conversationId);
            final Long dTurn = Long.valueOf(dialogueTurnOrdinal);
            boolean shortExpression = EXPRESSION_MODE_SHORT.equals(in.expressionMode());
