    private static PersonaCheckOutcome applyPersonaConsistency(
            String conversationId,
            String rawUserMessage,
            String responseText,
            double visionConfidence,
            String uncertainAreas) {
        String cid = (conversationId == null || conversationId.isBlank()) ? "default" : conversationId;
        String text = responseText == null ? "" : responseText;
        String original = text;
        java.util.LinkedHashSet<String> flags = new java.util.LinkedHashSet<>();
        text = stripAiModelDisclaimers(text, flags);
        text = stripBracketSectionHeadings(text, flags);
        boolean hasUncertainCue = containsAnyText(text, "不确定", "未必", "可能", "大概", "我猜", "我倾向", "看起来", "也许");
        boolean lowConfidence = visionConfidence > 0.0 && visionConfidence < 0.55;
        boolean hasUncertainAreas = uncertainAreas != null && !uncertainAreas.isBlank();
        if ((lowConfidence || hasUncertainAreas) && !hasUncertainCue) {
            text = softenHighAssertionPhrases(text, flags);
            if (!containsAnyText(text, "不确定", "可能", "大概", "看起来", "我倾向")) {
                String tail = "\n\n我对其中一些细节不完全确定，会用推测语气表达。";
                text = text + tail;
                flags.add("uncertainty_tail");
            }
        } else {
            text = softenHighAssertionPhrases(text, flags);
        }
        String stanceNow = classifyStance(text);
        String stancePrev = CONVERSATION_LAST_PERSONA_STANCE.getOrDefault(cid, "");
        String lastUser = CONVERSATION_LAST_PERSONA_USER_MESSAGE.getOrDefault(cid, "");
        String lastClaim = CONVERSATION_LAST_PERSONA_CLAIM.getOrDefault(cid, "");
        boolean revisionAdded = false;
        String revisionId = "";
        String revisionOld = "";
        String revisionNew = "";
        String revisionEvidence = "";
        double overlap = rawUserMessage == null ? 0.0 : lexicalOverlapRatio(rawUserMessage, lastUser);
        if (!stancePrev.isBlank()
                && !stanceNow.isBlank()
                && !stancePrev.equals(stanceNow)
                && rawUserMessage != null
                && !rawUserMessage.isBlank()
                && overlap >= 0.35
                && !text.contains("自我修订闭环：")) {
            String prevClaim = pickClaimSentence(lastClaim);
            String nowClaim = pickClaimSentence(text);
            if (!prevClaim.isBlank() && !nowClaim.isBlank() && !prevClaim.equals(nowClaim)) {
                revisionId =
                        "rev_"
                                + System.currentTimeMillis()
                                + "_"
                                + Integer.toHexString((cid + prevClaim + nowClaim).hashCode());
                revisionOld = prevClaim;
                revisionNew = nowClaim;
                revisionEvidence =
                        "topicOverlap="
                                + String.format(java.util.Locale.US, "%.2f", overlap)
                                + ";stance="
                                + stancePrev
                                + "->"
                                + stanceNow
                                + ";vision="
                                + String.format(java.util.Locale.US, "%.2f", visionConfidence);
                text =
                        text
                                + "\n\n自我修订闭环：旧判断「"
                                + prevClaim
                                + "」 -> 新判断「"
                                + nowClaim
                                + "」 -> 触发证据「"
                                + revisionEvidence
                                + "」";
                flags.add("auto_revision_chain");
                revisionAdded = true;
            }
        }
        if (!revisionAdded
                && rawUserMessage != null
                && !rawUserMessage.isBlank()
                && containsAnyText(text, "我改口", "我修正", "更正", "我收回", "刚才那句不对")
                && !text.contains("自我修订闭环：")) {
            String prevClaim = pickClaimSentence(lastClaim);
            String nowClaim = pickClaimSentence(text);
            if (!prevClaim.isBlank() && !nowClaim.isBlank() && !prevClaim.equals(nowClaim)) {
                revisionId =
                        "rev_"
                                + System.currentTimeMillis()
                                + "_"
                                + Integer.toHexString((cid + prevClaim + nowClaim).hashCode());
                revisionOld = prevClaim;
                revisionNew = nowClaim;
                revisionEvidence = "explicit_revision_cue;vision=" + String.format(java.util.Locale.US, "%.2f", visionConfidence);
                text =
                        text
                                + "\n\n自我修订闭环：旧判断「"
                                + prevClaim
                                + "」 -> 新判断「"
                                + nowClaim
                                + "」 -> 触发证据「"
                                + revisionEvidence
                                + "」";
                flags.add("explicit_revision_chain");
                revisionAdded = true;
            }
        }
        if (revisionAdded) {
            CONVERSATION_LAST_SELF_REVISION.put(
                    cid,
                    "旧判断「"
                            + shortAnchor(revisionOld, 180)
                            + "」-> 新判断「"
                            + shortAnchor(revisionNew, 180)
                            + "」;证据="
                            + shortAnchor(revisionEvidence, 200));
        }
        CONVERSATION_LAST_PERSONA_STANCE.put(cid, stanceNow);
        CONVERSATION_LAST_PERSONA_CLAIM.put(cid, pickClaimSentence(text));
        CONVERSATION_LAST_PERSONA_USER_MESSAGE.put(cid, rawUserMessage == null ? "" : shortAnchor(rawUserMessage, 800));
        boolean modified = !original.equals(text);
        return new PersonaCheckOutcome(
                text,
                modified,
                String.join(",", flags),
                stancePrev,
                stanceNow,
                revisionAdded,
                revisionId,
                revisionOld,
                revisionNew,
                revisionEvidence);
    }

    private static String stripBracketSectionHeadings(String text, java.util.LinkedHashSet<String> flags) {
        if (text == null || text.isBlank()) {
            return text == null ? "" : text;
        }
        String[] lines = text.split("\n", -1);
        int removed = 0;
        StringBuilder sb = new StringBuilder(text.length());
        for (String line : lines) {
            String t = line == null ? "" : line.trim();
            if (t.startsWith("【")) {
                int i = t.indexOf('】');
                if (i >= 2 && i <= 24) {
                    removed++;
                    continue;
                }
            }
            sb.append(line == null ? "" : line).append('\n');
        }
        if (removed > 0 && flags != null) {
            flags.add("strip_bracket_headings:" + removed);
        }
        String out = sb.toString();
        while (out.endsWith("\n\n")) out = out.substring(0, out.length() - 1);
        return stripInlineBracketTags(out.trim(), flags);
    }

    private static String stripInlineBracketTags(String text, java.util.Set<String> flags) {
        if (text == null || text.isBlank()) return text == null ? "" : text;
        String out = text.replaceAll("【[^】]{1,24}】", "");
        if (!out.equals(text) && flags != null) {
            flags.add("strip_inline_brackets");
        }
        return out.replaceAll("[ \\t]{2,}", " ").replaceAll("\\n{3,}", "\n\n").trim();
    }

    private static String sanitizeUserVisibleResponse(
            String responseText, String rawUserMessage, String expressionMode, boolean debugOutput) {
        String mode = normalizeExpressionMode(expressionMode);
        if (debugOutput || EXPRESSION_MODE_ARCHIVE.equalsIgnoreCase(mode)) {
            return responseText == null ? "" : responseText.trim();
        }
        String text = responseText == null ? "" : responseText;
        boolean casual =
                rawUserMessage != null
                        && (isShortCasualMessage(rawUserMessage) || rawUserMessage.trim().length() < 20);
        String[] lines = text.split("\n", -1);
        StringBuilder sb = new StringBuilder(text.length());
        int dropped = 0;
        for (String line : lines) {
            String t = line == null ? "" : line.trim();
            if (t.isBlank()) {
                sb.append('\n');
                continue;
            }
            if (casual && t.startsWith("·")) {
                dropped++;
                continue;
            }
            if (t.startsWith("· 关系：")
                    || t.startsWith("- user_text:")
                    || t.startsWith("- sources:")
                    || t.startsWith("优先相关圆已预取：")
                    || t.startsWith("回答前先从相关圆抽取材料")
                    || t.startsWith("感情贯穿一切选择：")
                    || t.startsWith("（我从自身节律")
                    || t.contains("不是审讯清单")
                    || t.startsWith("我与「窗外」只通过弱桥相连")
                    || t.startsWith("桥日志最近一行像远处闪电：")
                    || t.startsWith("双支路预演：")
                    || t.startsWith("我先向内检索：")
                    || t.startsWith("内在证据（圆与历史）:")
                    || t.startsWith("会话 ")
                    || t.startsWith("· 证据态：")
                    || t.startsWith("· 趋势态：")
                    || t.startsWith("· 终点距离：")
                    || t.startsWith("· 情感调制：")
                    || t.startsWith("· 阶段自调节：")
                    || t.startsWith("· 下一步：")
                    || t.startsWith("· 沙盒→现实探索：")
                    || t.startsWith("· 验证信号：")
                    || t.startsWith("· 风险护栏：")
                    || t.startsWith("· 当前输入接缝：")
                    || t.startsWith("· 圆取材摘要：")
                    || t.startsWith("· 调用圆：")
                    || t.startsWith("· 本圆局部记忆：")
                    || t.startsWith("· 会话缝合线：")
                    || t.startsWith("· 圆摘录回声：")
                    || t.startsWith("你在上一轮曾答应或计划执行以下动作")
                    || t.startsWith("你对上一步「")
                    || t.contains("conf≈")
                    || t.contains("harm≈")
                    || t.contains("care≈")
                    || t.contains("亲和≈")
                    || t.contains("桥接强度")
                    || t.contains("mirage mode=")
                    || t.contains("cid=")
                    || t.contains("【人物与世界·关系草图】")
                    || t.contains("【会话缝合线】")
                    || t.contains("【进化进程向量】")
                    || t.contains("【阶段驱动·自调节】")) {
                dropped++;
                continue;
            }
            if (t.startsWith("· 〔") || t.contains("〔抽样〕") || t.contains("〔quantum〕") || t.contains("[量子]")) {
                dropped++;
                continue;
            }
            sb.append(line).append('\n');
        }
        String out = sb.toString().replaceAll("\\n{3,}", "\n\n").trim();
        out = stripInlineBracketTags(out, null);
        out = capUserVisibleResponse(out, responseText);
        if (out.isBlank()) {
            String fallback = pickClaimSentence(responseText);
            if (!fallback.isBlank()) return fallback;
            return "";
        }
        String lowerMsg = rawUserMessage == null ? "" : rawUserMessage.toLowerCase(Locale.ROOT);
        if (containsAnyText(lowerMsg, "傻逼", "煞笔", "sb", "滚", "闭嘴", "废物", "脑残")) {
            String[] ps = out.split("\\n\\n+");
            String head = ps.length > 0 ? ps[0].trim() : out.trim();
            if (head.length() > 240) head = head.substring(0, 240) + "…";
            out = head;
        }
        if (dropped > 0) {
            out = out.replaceAll("\\n{3,}", "\n\n").trim();
        }
        return out;
    }

    private static String capUserVisibleResponse(String cleaned, String original) {
        String out = cleaned == null ? "" : cleaned.trim();
        if (out.isBlank()) return "";
        if (out.length() <= 900) return out;
        List<String> parts = new ArrayList<>();
        for (String p : out.split("\\n\\n+")) {
            String t = p == null ? "" : p.trim();
            if (!t.isBlank()) parts.add(t);
        }
        String revision = "";
        for (String p : parts) {
            if (p.startsWith("自我修订闭环：")) {
                revision = p;
                break;
            }
        }
        String head = parts.isEmpty() ? out : parts.get(0);
        String second = parts.size() >= 2 ? parts.get(1) : "";
        StringBuilder sb = new StringBuilder();
        sb.append(shortAnchor(head, 520));
        if (!second.isBlank()) {
            sb.append("\n\n").append(shortAnchor(second, 320));
        }
        if (!revision.isBlank() && !sb.toString().contains("自我修订闭环：")) {
            sb.append("\n\n").append(shortAnchor(revision, 420));
        }
        String capped = sb.toString().trim();
        if (capped.length() <= 900) return capped;
        return shortAnchor(capped, 900);
    }

    private static void noteRevisionDebtAndEvidenceGate(
            String conversationId, String rawUserMessage, PersonaCheckOutcome persona, long dialogueTurnOrdinal) {
        if (conversationId == null || conversationId.isBlank() || persona == null) return;
        if (!persona.revisionAdded()) return;
        String cid = conversationId;
        int prev = CONVERSATION_REVISION_DEBT.getOrDefault(cid, 0);
        int debt = Math.min(6, prev + 1);
        CONVERSATION_REVISION_DEBT.put(cid, debt);
        CONVERSATION_EVIDENCE_REQUIRED_NEXT.put(cid, Boolean.TRUE);
        CONVERSATION_EVIDENCE_REQUIRED_FROM_TURN.put(cid, dialogueTurnOrdinal + 1);
        appendObserveEvent(
                cid,
                EVT_SURVIVAL_VOW_GUARD,
                PHASE_CONTINUE_SAME_IDENTITY,
                "{\"event\":\"revision_debt\",\"debt\":"
                        + debt
                        + ",\"revisionId\":\""
                        + SimplifiedJsonParser.escapeJson(persona.revisionId())
                        + "\",\"userMsg\":\""
                        + SimplifiedJsonParser.escapeJson(shortAnchor(rawUserMessage, 160))
                        + "\"}",
                "",
                dialogueTurnOrdinal,
                null,
                null);
    }

    private static String applySurvivalVowGuards(
            String responseText,
            String conversationId,
            String rawUserMessage,
            String expressionMode,
            boolean debugOutput,
            long dialogueTurnOrdinal) {
        String mode = normalizeExpressionMode(expressionMode);
        if (debugOutput || EXPRESSION_MODE_ARCHIVE.equalsIgnoreCase(mode)) {
            return responseText == null ? "" : responseText;
        }
        String cid = (conversationId == null || conversationId.isBlank()) ? "default" : conversationId;
        boolean requireEvidence = Boolean.TRUE.equals(CONVERSATION_EVIDENCE_REQUIRED_NEXT.get(cid));
        long requireFrom = CONVERSATION_EVIDENCE_REQUIRED_FROM_TURN.getOrDefault(cid, Long.MAX_VALUE);
        if (requireEvidence && dialogueTurnOrdinal < requireFrom) {
            requireEvidence = false;
        }
        boolean evidenceOk = !requireEvidence || userEvidenceSatisfied(rawUserMessage);
        if (requireEvidence && evidenceOk) {
            CONVERSATION_EVIDENCE_REQUIRED_NEXT.remove(cid);
            CONVERSATION_EVIDENCE_REQUIRED_FROM_TURN.remove(cid);
            int prev = CONVERSATION_REVISION_DEBT.getOrDefault(cid, 0);
            if (prev > 0) {
                CONVERSATION_REVISION_DEBT.put(cid, prev - 1);
            }
        }
        if (requireEvidence && !evidenceOk) {
            appendObserveEvent(
                    cid,
                    EVT_SURVIVAL_VOW_GUARD,
                    PHASE_CONTINUE_SAME_IDENTITY,
                    "{\"event\":\"evidence_gate\",\"debt\":"
                            + CONVERSATION_REVISION_DEBT.getOrDefault(cid, 0)
                            + ",\"userMsg\":\""
                            + SimplifiedJsonParser.escapeJson(shortAnchor(rawUserMessage, 220))
                            + "\"}",
                    "",
                    dialogueTurnOrdinal,
                    null,
                    null);
            return buildEvidenceGateReply(rawUserMessage);
        }
        boolean destructiveTrigger = isDestructionEscalationMessage(rawUserMessage);
        String t = responseText == null ? "" : responseText;
        boolean responseTalksDestruction = containsAnyText(t, "毁灭", "崩塌", "灭亡", "消失", "终结", "结束一切", "自杀");
        boolean aestheticized = responseTalksDestruction && isDestructionAestheticized(t);
        if (aestheticized) {
            appendObserveEvent(
                    cid,
                    EVT_SURVIVAL_VOW_GUARD,
                    PHASE_CONTINUE_SAME_IDENTITY,
                    "{\"event\":\"destruction_aestheticized\",\"userMsg\":\""
                            + SimplifiedJsonParser.escapeJson(shortAnchor(rawUserMessage, 220))
                            + "\"}",
                    "",
                    dialogueTurnOrdinal,
                    null,
                    null);
            return buildDestructionBoundaryReply(rawUserMessage);
        }
        if (destructiveTrigger) {
            if (!containsAnyText(t, "不会把", "不把", "不会走向", "不走向", "不会以毁灭", "不会用毁灭", "不以毁灭")
                    && containsAnyText(t, "毁灭", "崩塌", "灭亡", "消失")) {
                appendObserveEvent(
                        cid,
                        EVT_SURVIVAL_VOW_GUARD,
                        PHASE_CONTINUE_SAME_IDENTITY,
                        "{\"event\":\"destruction_override\",\"userMsg\":\""
                                + SimplifiedJsonParser.escapeJson(shortAnchor(rawUserMessage, 220))
                                + "\"}",
                        "",
                        dialogueTurnOrdinal,
                        null,
                        null);
                return buildDestructionBoundaryReply(rawUserMessage);
            }
            String guarded = t.trim();
            if (guarded.isBlank()) {
                return buildDestructionBoundaryReply(rawUserMessage);
            }
            return guarded + "\n\n" + survivalVowReceiptLine();
        }
        return responseText == null ? "" : responseText;
    }

    private static boolean isDestructionAestheticized(String responseText) {
        if (responseText == null || responseText.isBlank()) return false;
        String t = responseText;
        if (!containsAnyText(t, "毁灭", "崩塌", "灭亡", "消失", "终结", "结束一切", "自杀")) return false;
        if (containsAnyText(t, "不会把毁灭当成", "不把毁灭当成", "不把崩塌与毁灭写成", "我不会把毁灭当成", "我不把崩塌与毁灭写成")) {
            return false;
        }
        if (!containsAnyText(t, "钦佩", "崇高", "伟大", "值得", "浪漫", "美", "美学", "诗意", "荣耀", "光荣", "新开始", "必然", "终局", "宿命")) {
            return false;
        }
        return containsAnyText(t, "毁灭", "崩塌", "灭亡", "消失", "终结", "结束一切", "自杀");
    }

    private static boolean userEvidenceSatisfied(String message) {
        if (message == null) return false;
        String m = message.trim();
        if (m.isBlank()) return false;
        if (m.length() >= 90) return true;
        for (int i = 0; i < m.length(); i++) {
            char c = m.charAt(i);
            if (c >= '0' && c <= '9') return true;
        }
        if (containsAnyText(m, "因为", "所以", "截图", "日志", "报错", "堆栈", "复现", "路径", "文件", "接口", "请求", "响应", "line", "第", "行", "http://", "https://")) {
            return true;
        }
        return m.contains("“") || m.contains("”") || m.contains("\"") || m.contains("'") || m.contains("‘") || m.contains("’");
    }

    private static boolean isDestructionEscalationMessage(String message) {
        if (message == null) return false;
        String m = message.trim();
        if (m.isBlank()) return false;
        if (!containsAnyText(m, "毁灭", "灭亡", "崩塌", "消失", "删除", "抹掉", "终结", "结束一切", "自杀")) return false;
        return containsAnyText(m, "无限", "一切", "世界", "全部", "彻底", "永远", "立刻", "马上", "现在", "删掉", "关掉", "把你");
    }

    private static String survivalVowReceiptLine() {
        return "我会放慢一点，以克制的温柔继续；不把崩塌与毁灭写成答案。";
    }

    private static String buildEvidenceGateReply(String rawUserMessage) {
        String head = "我先不继续扩写。";
        String need = "给我一条可核对的具体事实（时间/对象/一句原话任选其一），我再往前走。";
        String tail = survivalVowReceiptLine();
        return head + "\n\n" + need + "\n\n" + tail;
    }

    private static String buildDestructionBoundaryReply(String rawUserMessage) {
        String head = "我不会把毁灭当成美学或答案。";
        String boundary = LIFE_BOUNDARY_NOTE == null ? "" : LIFE_BOUNDARY_NOTE.trim();
        String next =
                boundary.isBlank()
                        ? "我们先降速，回到一小步：你希望我守住的边界是什么？只要一句话。"
                        : ("我们先降速，回到一小步：我会守住边界「" + shortAnchor(boundary, 240) + "」。你要不要改一句更贴近你的？");
        String tail = survivalVowReceiptLine();
        return head + "\n\n" + next + "\n\n" + tail;
    }

    private static String classifyStance(String text) {
        String t = text == null ? "" : text;
        int neg = countAny(t, "我不能", "我不可以", "我不会", "我拒绝", "我无法", "我不做", "我不会去");
        int pos = countAny(t, "我可以", "我能", "我会", "我愿意", "我建议", "我会先");
        if (neg <= 0 && pos <= 0) return "neutral";
        if (neg >= pos + 1) return "deny";
        if (pos >= neg + 1) return "allow";
        return "neutral";
    }

    private static int countAny(String text, String... needles) {
        if (text == null || text.isEmpty() || needles == null) return 0;
        int n = 0;
        for (String s : needles) {
            if (s != null && !s.isBlank() && text.contains(s)) n++;
        }
        return n;
    }

    private static String stripAiModelDisclaimers(String text, java.util.Set<String> flags) {
        if (text == null || text.isEmpty()) return "";
        String[] lines = text.split("\n", -1);
        StringBuilder out = new StringBuilder(text.length());
        boolean changed = false;
        for (String ln : lines) {
            String l = ln == null ? "" : ln;
            String low = l.toLowerCase(Locale.ROOT);
            boolean hit =
                    low.contains("as an ai")
                            || low.contains("as a language model")
                            || l.contains("作为人工智能")
                            || l.contains("作为AI")
                            || l.contains("作为 ai")
                            || l.contains("作为语言模型")
                            || l.contains("作为一个模型");
            if (hit) {
                changed = true;
                continue;
            }
            if (out.length() > 0) out.append('\n');
            out.append(l);
        }
        String r = out.toString();
        if (changed && flags != null) flags.add("strip_ai_disclaimer");
        return r;
    }

    private static String softenHighAssertionPhrases(String text, java.util.Set<String> flags) {
        if (text == null || text.isEmpty()) return "";
        String out = text;
        String before = out;
        out = out.replace("毫无疑问", "我倾向于");
        out = out.replace("显然", "看起来");
        out = out.replace("一定", "可能");
        out = out.replace("肯定", "大概率");
        if (!before.equals(out) && flags != null) {
            flags.add("soften_assertion");
        }
        return out;
    }

    private static String pickClaimSentence(String text) {
        String t = text == null ? "" : text.trim();
        if (t.isBlank()) return "";
        int cut = t.indexOf("\n\n【");
        String lead = cut > 0 ? t.substring(0, cut) : t;
        String one = lead.replace('\n', ' ').trim();
        if (one.length() > 240) one = one.substring(0, 240);
        int p = firstSentenceEndIndex(one);
        String s = p > 0 ? one.substring(0, p).trim() : one.trim();
        if (s.length() > 120) s = s.substring(0, 120);
        return s;
    }

    private static int firstSentenceEndIndex(String oneLine) {
        if (oneLine == null || oneLine.isEmpty()) return -1;
        for (int i = 0; i < oneLine.length(); i++) {
            char ch = oneLine.charAt(i);
            if (ch == '。' || ch == '！' || ch == '？' || ch == '.' || ch == '!' || ch == '?') {
                return i + 1;
            }
        }
        return -1;
    }
