                CONVERSATION_AUTONOMY_STATE.getOrDefault(cid, AutonomyState.LISTENING).name();
        String deferredGoals = CONVERSATION_DEFERRED_GOAL_IDS.getOrDefault(cid, "");
        double innerQuestionDrive = CONVERSATION_INNER_QUESTION_DRIVE.getOrDefault(cid, 0.46);
        String lastQuestionCue = CONVERSATION_LAST_QUESTION_CUE.getOrDefault(cid, "");
        String questionStyleVector =
                CONVERSATION_QUESTION_STYLE_VECTOR.getOrDefault(cid, "0.25,0.25,0.25,0.25");
