    private static String buildOpeningDigestLine(String conversationId) {
        String cid =
                conversationId == null || conversationId.isBlank() ? "default" : conversationId.trim();
        List<String> lines = new ArrayList<>();
        String sum = CONVERSATION_LAST_SUMMARY.getOrDefault(cid, "");
        if (sum != null && !sum.isBlank()) {
            lines.add("摘要：" + shortAnchor(sum, 200));
        }
        String stitch =
                buildStitchHistoryContext(
                        cid,
                        resolveDynamicStitchWindow(
                                emotionCore, CONVERSATION_EVIDENCE_LEVEL.getOrDefault(cid, "medium")));
        if (stitch != null && !stitch.isBlank()) {
            lines.add("缝合：" + shortAnchor(stitch, 160));
        }
        String mid = CONVERSATION_MID_RELATION_MEMORY.getOrDefault(cid, "");
        if (mid != null && !mid.isBlank()) {
            lines.add("关系中：" + shortAnchor(mid, 140));
        }
        if (lines.isEmpty()) {
            return "";
        }
        int n = Math.min(3, lines.size());
        return String.join("\n", lines.subList(0, n));
    }

    private static String buildSessionStitchSummary(
            String conversationId,
            String userMessage,
            String responseText,
            String circleName,
            String evidenceLevel,
            String actionStatus) {
        String cid = conversationId == null || conversationId.isBlank() ? "default" : conversationId;
        String prev = CONVERSATION_LAST_SUMMARY.getOrDefault(cid, "");
        StringBuilder sb = new StringBuilder();
        sb.append("cid=").append(cid).append(" ");
        sb.append("circle=").append(circleName == null ? "none" : circleName).append(" ");
        sb.append("evidence=").append(evidenceLevel == null ? "medium" : evidenceLevel).append(" ");
        if (actionStatus != null && !actionStatus.isBlank()) {
            sb.append("action=").append(actionStatus).append(" ");
        }
        sb.append("| user=").append(shortAnchor(userMessage, 140));
        sb.append(" | reply=").append(shortAnchor(responseText, 160));
        if (!prev.isBlank()) {
            sb.append(" | prev=").append(shortAnchor(prev, 120));
        }
        return shortAnchor(sb.toString(), 560);
    }

    private static String emotionInfluenceLabel(EmotionCore core) {
        if (core == null) return "emotion=unknown";
        double mood = core.getMood();
        double impulse = core.getImpulse();
        double love = core.getTranscendentalLove();
        double arousal = core.getArousal();
        String bandMood = mood < 0.34 ? "low_mood" : (mood < 0.62 ? "mid_mood" : "high_mood");
        String bandImpulse = impulse > 0.62 ? "high_impulse" : (impulse < 0.32 ? "low_impulse" : "mid_impulse");
        String bandLove = love > 0.55 ? "high_love" : (love < 0.28 ? "low_love" : "mid_love");
        String bandArousal = arousal < 0.28 ? "low_arousal" : (arousal > 0.65 ? "high_arousal" : "mid_arousal");
        return bandMood + "|" + bandImpulse + "|" + bandLove + "|" + bandArousal + "|mode=" + core.getMode().name();
    }

    private static synchronized void appendStitchHistory(String conversationId, String stitch) {
        if (conversationId == null || conversationId.isBlank() || stitch == null || stitch.isBlank()) {
            return;
        }
        ArrayDeque<String> q = CONVERSATION_STITCH_HISTORY.computeIfAbsent(conversationId, k -> new ArrayDeque<>());
        q.addLast(stitch);
        while (q.size() > STITCH_HISTORY_MAX) {
            q.removeFirst();
        }
    }

    private static int resolveDynamicStitchWindow(EmotionCore core, String evidenceLevel) {
        int base = 3;
        String ev = evidenceLevel == null ? "medium" : evidenceLevel.toLowerCase(Locale.ROOT);
        if ("high".equals(ev)) {
            base = 2;
        } else if ("low".equals(ev)) {
            base = 4;
        }
        if (core == null) {
            return Math.max(2, Math.min(STITCH_HISTORY_MAX, base));
        }
        if (core.getMode() == LifeMode.DREAMING) {
            base = Math.min(STITCH_HISTORY_MAX, base + 1);
        }
        if (core.getImpulse() > 0.66 && core.getArousal() > 0.58) {
            base = Math.max(2, base - 1);
        } else if (core.getArousal() < 0.26 || core.getMood() < 0.34) {
            base = Math.min(STITCH_HISTORY_MAX, base + 1);
        }
        return Math.max(2, Math.min(STITCH_HISTORY_MAX, base));
    }

    private static String explainDynamicStitchWindow(EmotionCore core, String evidenceLevel) {
        String ev = evidenceLevel == null ? "medium" : evidenceLevel.toLowerCase(Locale.ROOT);
        if (core == null) {
            return "无情感上下文，按证据态窗口。";
        }
        StringBuilder why = new StringBuilder();
        why.append("evidence=").append(ev);
        if (core.getMode() == LifeMode.DREAMING) {
            why.append(" + dream_mode扩窗");
        }
        if (core.getImpulse() > 0.66 && core.getArousal() > 0.58) {
            why.append(" + high_drive收束");
        } else if (core.getArousal() < 0.26 || core.getMood() < 0.34) {
            why.append(" + low_arousal_or_low_mood扩窗");
        } else {
            why.append(" + mid_phase平衡");
        }
        return why.toString();
    }

    private static synchronized String buildStitchHistoryContext(String conversationId, int maxItems) {
        if (conversationId == null || conversationId.isBlank()) {
            return "";
        }
        ArrayDeque<String> q = CONVERSATION_STITCH_HISTORY.get(conversationId);
        if (q == null || q.isEmpty()) {
            String one = CONVERSATION_LAST_SUMMARY.getOrDefault(conversationId, "");
            if (one.isBlank()) return "";
            return "【会话缝合线】\n· " + shortAnchor(one, 260);
        }
        int n = Math.min(Math.max(1, maxItems), q.size());
        String[] arr = q.toArray(new String[0]);
        StringBuilder sb = new StringBuilder();
        sb.append("【会话缝合线·最近").append(n).append("轮】\n");
        for (int i = arr.length - n; i < arr.length; i++) {
            sb.append("· ").append(shortAnchor(arr[i], 220)).append("\n");
        }
        return sb.toString().trim();
    }

    private static synchronized String serializeStitchHistory(String conversationId) {
        ArrayDeque<String> q = CONVERSATION_STITCH_HISTORY.get(conversationId);
        if (q == null || q.isEmpty()) return "";
        StringBuilder sb = new StringBuilder();
        boolean first = true;
        for (String s : q) {
            if (!first) sb.append("||");
            first = false;
            sb.append(escState(shortAnchor(s, 260)));
        }
        return sb.toString();
    }

    private static synchronized void restoreStitchHistory(String conversationId, String raw) {
        if (conversationId == null || conversationId.isBlank() || raw == null || raw.isBlank()) {
            return;
        }
        String[] parts = raw.split("\\|\\|", -1);
        ArrayDeque<String> q = CONVERSATION_STITCH_HISTORY.computeIfAbsent(conversationId, k -> new ArrayDeque<>());
        for (String p : parts) {
            String one = unescState(p).trim();
            if (!one.isBlank()) {
                q.addLast(one);
                while (q.size() > STITCH_HISTORY_MAX) {
                    q.removeFirst();
                }
            }
        }
    }

    private static synchronized String serializeShortContext(String conversationId) {
        ArrayDeque<String> q = CONVERSATION_SHORT_CONTEXT.get(conversationId);
        if (q == null || q.isEmpty()) return "";
        StringBuilder sb = new StringBuilder();
        boolean first = true;
        for (String s : q) {
            if (s == null || s.isBlank()) continue;
            if (!first) sb.append("||");
            first = false;
            sb.append(escState(shortAnchor(s, 260)));
        }
        return sb.toString();
    }

    private static synchronized void restoreShortContext(String conversationId, String raw) {
        if (conversationId == null || conversationId.isBlank() || raw == null || raw.isBlank()) return;
        String[] parts = raw.split("\\|\\|", -1);
        ArrayDeque<String> q = CONVERSATION_SHORT_CONTEXT.computeIfAbsent(conversationId, k -> new ArrayDeque<>());
        for (String p : parts) {
            String one = unescState(p).trim();
            if (one.isBlank()) continue;
            q.addLast(one);
            while (q.size() > 14) q.removeFirst();
        }
    }

    private static String buildConversationStateAllJson(int limit) {
        List<String> ids = new ArrayList<>(CONVERSATION_EVIDENCE_LEVEL.keySet());
        for (String cid : CONVERSATION_LAST_TOUCH_MS.keySet()) {
            if (!ids.contains(cid)) ids.add(cid);
        }
        ids.sort(
                (a, b) ->
                        Double.compare(conversationPriorityScore(b), conversationPriorityScore(a)));
        StringBuilder sb = new StringBuilder();
        sb.append("{\"count\":").append(ids.size()).append(",\"items\":[");
        int n = Math.min(limit, ids.size());
        for (int i = 0; i < n; i++) {
            if (i > 0) sb.append(',');
            sb.append(buildConversationStateJson(ids.get(i)));
        }
        sb.append("]}");
        return sb.toString();
    }

    private static String buildGlobalConversationVisualizationJson(int interventionTopN) {
        List<String> ids = new ArrayList<>(CONVERSATION_EVIDENCE_LEVEL.keySet());
        for (String cid : CONVERSATION_LAST_TOUCH_MS.keySet()) {
            if (!ids.contains(cid)) ids.add(cid);
        }
        for (String cid : CONVERSATION_SELF_REGULATION.keySet()) {
            if (!ids.contains(cid)) ids.add(cid);
        }
        for (String cid : CONVERSATION_PROGRESS_TREND.keySet()) {
            if (!ids.contains(cid)) ids.add(cid);
        }
        for (String cid : CONVERSATION_GOAL_STAGE.keySet()) {
            if (!ids.contains(cid)) ids.add(cid);
        }
        int evidenceLow = 0, evidenceMedium = 0, evidenceHigh = 0;
        int trendDown = 0, trendFlat = 0, trendUp = 0;
        int stageAwakening = 0, stageStabilizing = 0, stageIntegrating = 0, stageApproaching = 0;
        int regMicro = 0, regBalanced = 0, regParallel = 0;
        int verifyStrict = 0, verifyBalanced = 0, verifyClosure = 0;
        for (String cid : ids) {
            String ev = CONVERSATION_EVIDENCE_LEVEL.getOrDefault(cid, "medium").toLowerCase(Locale.ROOT);
            if ("low".equals(ev)) evidenceLow++;
            else if ("high".equals(ev)) evidenceHigh++;
            else evidenceMedium++;

            String tr = CONVERSATION_PROGRESS_TREND.getOrDefault(cid, "flat").toLowerCase(Locale.ROOT);
            if ("down".equals(tr)) trendDown++;
            else if ("up".equals(tr)) trendUp++;
            else trendFlat++;

            String st = CONVERSATION_GOAL_STAGE.getOrDefault(cid, "awakening").toLowerCase(Locale.ROOT);
            if ("stabilizing".equals(st)) stageStabilizing++;
            else if ("integrating".equals(st)) stageIntegrating++;
            else if ("approaching_goal".equals(st)) stageApproaching++;
            else stageAwakening++;

            String reg = CONVERSATION_SELF_REGULATION.getOrDefault(cid, "");
            String action = parseSelfRegField(reg, "action");
            if ("micro".equals(action)) regMicro++;
            else if ("parallel".equals(action)) regParallel++;
            else regBalanced++;
            String verify = parseSelfRegField(reg, "verify");
            if ("strict".equals(verify)) verifyStrict++;
            else if ("closure".equals(verify)) verifyClosure++;
            else verifyBalanced++;
        }

        ids.sort((a, b) -> Double.compare(interventionPriorityScore(b), interventionPriorityScore(a)));
        int topN = Math.min(Math.max(1, interventionTopN), ids.size());
        StringBuilder top = new StringBuilder();
        top.append('[');
        for (int i = 0; i < topN; i++) {
            String cid = ids.get(i);
            if (i > 0) top.append(',');
            top.append("{\"conversationId\":\"")
                    .append(SimplifiedJsonParser.escapeJson(cid))
                    .append("\",\"priority\":")
                    .append(String.format(java.util.Locale.US, "%.2f", interventionPriorityScore(cid)))
                    .append(",\"evidence\":\"")
                    .append(SimplifiedJsonParser.escapeJson(CONVERSATION_EVIDENCE_LEVEL.getOrDefault(cid, "medium")))
                    .append("\",\"trend\":\"")
                    .append(SimplifiedJsonParser.escapeJson(CONVERSATION_PROGRESS_TREND.getOrDefault(cid, "flat")))
                    .append("\",\"goalStage\":\"")
                    .append(SimplifiedJsonParser.escapeJson(CONVERSATION_GOAL_STAGE.getOrDefault(cid, "awakening")))
                    .append("\",\"selfReg\":\"")
                    .append(SimplifiedJsonParser.escapeJson(CONVERSATION_SELF_REGULATION.getOrDefault(cid, "")))
                    .append("\"}");
        }
        top.append(']');

        return "{"
                + "\"conversationCount\":"
                + ids.size()
                + ",\"evidenceDist\":{\"low\":"
                + evidenceLow
                + ",\"medium\":"
                + evidenceMedium
                + ",\"high\":"
                + evidenceHigh
                + "},\"trendDist\":{\"down\":"
                + trendDown
                + ",\"flat\":"
                + trendFlat
                + ",\"up\":"
                + trendUp
                + "},\"goalStageDist\":{\"awakening\":"
                + stageAwakening
                + ",\"stabilizing\":"
                + stageStabilizing
                + ",\"integrating\":"
                + stageIntegrating
                + ",\"approaching_goal\":"
                + stageApproaching
                + "},\"selfRegActionDist\":{\"micro\":"
                + regMicro
                + ",\"balanced\":"
                + regBalanced
                + ",\"parallel\":"
                + regParallel
                + "},\"selfRegVerifyDist\":{\"strict\":"
                + verifyStrict
                + ",\"balanced\":"
                + verifyBalanced
                + ",\"closure\":"
                + verifyClosure
                + "},\"interventionQueue\":"
                + top
                + "}";
    }

    private static String parseSelfRegField(String oneLine, String key) {
        if (oneLine == null || oneLine.isBlank() || key == null || key.isBlank()) {
            return "";
        }
        String token = key + "=";
        int i = oneLine.indexOf(token);
        if (i < 0) return "";
        int start = i + token.length();
        int end = oneLine.indexOf(' ', start);
        if (end < 0) end = oneLine.length();
        return oneLine.substring(start, end).trim().toLowerCase(Locale.ROOT);
    }

    private static double interventionPriorityScore(String conversationId) {
        double score = conversationPriorityScore(conversationId);
        if (conversationId == null || conversationId.isBlank()) return score;
        String reg = CONVERSATION_SELF_REGULATION.getOrDefault(conversationId, "");
        String action = parseSelfRegField(reg, "action");
        String verify = parseSelfRegField(reg, "verify");
        if ("micro".equals(action)) score += 220.0;
        if ("strict".equals(verify)) score += 280.0;
        if ("closure".equals(verify)) score += 140.0;
        String trend = CONVERSATION_PROGRESS_TREND.getOrDefault(conversationId, "flat");
        if ("down".equalsIgnoreCase(trend)) score += 420.0;
        return score;
    }

    /** 每个用户对话轮次开始时调用一次，得到本会话内单调序号（用于稳定 turnId）。 */
    private static synchronized long allocNextDialogueTurnOrdinal(String conversationId) {
        String cid = (conversationId == null || conversationId.isBlank()) ? "default" : conversationId;
        return CONVERSATION_TURN_COUNTER.merge(cid, 1L, Long::sum);
    }

    private static synchronized long nextMonologueBeatSeq(String scopeKey) {
        String k = (scopeKey == null || scopeKey.isBlank()) ? "default" : scopeKey.trim();
        return CONVERSATION_BEAT_COUNTER.merge(k, 1L, Long::sum);
    }

    /** 重启后恢复线性记忆游标；缺省文件则从 0 起，首条 prev 为空（与「碎片记忆」一致）。 */
    private static void loadObserveLinearMemoryState() {
        try {
            if (!Files.exists(OBSERVE_LINEAR_MEMORY_STATE_PATH)) {
                return;
            }
            List<String> lines = Files.readAllLines(OBSERVE_LINEAR_MEMORY_STATE_PATH, StandardCharsets.UTF_8);
            if (lines.isEmpty()) {
                return;
            }
            String seqLine = lines.get(0).trim();
            if (!seqLine.isEmpty()) {
                GLOBAL_MEMORY_CHAIN_SEQ.set(Long.parseLong(seqLine));
            }
            if (lines.size() >= 2) {
                LAST_GLOBAL_MEMORY_EVENT_ID = lines.get(1).trim();
            }
        } catch (Exception ignored) {
        }
    }

    private static void persistObserveLinearMemoryState(long lastMemorySeq, String lastEventId) {
        try {
            Files.createDirectories(OBSERVE_LINEAR_MEMORY_STATE_PATH.getParent());
            String body =
                    Long.toString(lastMemorySeq)
                            + System.lineSeparator()
                            + (lastEventId == null ? "" : lastEventId)
                            + System.lineSeparator();
            Files.writeString(
                    OBSERVE_LINEAR_MEMORY_STATE_PATH,
                    body,
                    StandardCharsets.UTF_8,
                    StandardOpenOption.CREATE,
                    StandardOpenOption.TRUNCATE_EXISTING);
        } catch (IOException ignored) {
        }
    }

