    private static String buildObserveTimelineJson(String conversationId, int limit) {
        String cid = (conversationId == null || conversationId.isBlank()) ? "default" : conversationId;
        ArrayDeque<String> q = CONVERSATION_OBSERVE_TIMELINE.get(cid);
        int total = q == null ? 0 : q.size();
        int autonomousCount = 0;
        long lastAutonomousTs = 0L;
        int proactiveBeatCount = 0;
        int proactiveSuppressedRecentTouch = 0;
        int proactiveSuppressedDuplicate = 0;
        int sandboxProbeAccepted = 0;
        int sandboxProbeRejected = 0;
        int sandboxProbeUnanswerable = 0;
        if (q != null && !q.isEmpty()) {
            for (String item : q) {
                if (item == null || item.isBlank()) continue;
                if (item.contains("\"isAutonomous\":true")) {
                    autonomousCount++;
                    long ts = extractJsonLongField(item, "ts");
                    if (ts > lastAutonomousTs) lastAutonomousTs = ts;
                }
                if (item.contains("\"type\":\"proactive_beat\"")) {
                    proactiveBeatCount++;
                }
                if (item.contains("\"type\":\"proactive_suppressed\"")) {
                    if (item.contains("recent_user_touch")) {
                        proactiveSuppressedRecentTouch++;
                    } else if (item.contains("duplicate")) {
                        proactiveSuppressedDuplicate++;
                    }
                }
                if (item.contains("\"type\":\"sandbox_probe_validation\"")) {
                    if (item.contains("\"status\":\"accepted\"")) sandboxProbeAccepted++;
                    else if (item.contains("\"status\":\"rejected\"")) sandboxProbeRejected++;
                    else if (item.contains("\"status\":\"unanswerable\"")) sandboxProbeUnanswerable++;
                }
            }
        }
        double autonomousRate = total <= 0 ? 0.0 : (double) autonomousCount / (double) total;
        StringBuilder sb = new StringBuilder();
        sb.append("{\"conversationId\":\"")
                .append(SimplifiedJsonParser.escapeJson(cid))
                .append("\",\"count\":")
                .append(total)
                .append(",\"autonomousCount\":")
                .append(autonomousCount)
                .append(",\"autonomousRate\":")
                .append(String.format(java.util.Locale.US, "%.4f", autonomousRate))
                .append(",\"lastAutonomousTs\":")
                .append(lastAutonomousTs)
                .append(",\"proactiveBeatCount\":")
                .append(proactiveBeatCount)
                .append(",\"proactiveSuppressedRecentUserTouch\":")
                .append(proactiveSuppressedRecentTouch)
                .append(",\"proactiveSuppressedDuplicate\":")
                .append(proactiveSuppressedDuplicate)
                .append(",\"sandboxProbeAccepted\":")
                .append(sandboxProbeAccepted)
                .append(",\"sandboxProbeRejected\":")
                .append(sandboxProbeRejected)
                .append(",\"sandboxProbeUnanswerable\":")
                .append(sandboxProbeUnanswerable)
                .append(",\"items\":[");
        if (q != null && !q.isEmpty()) {
            int n = Math.min(Math.max(1, limit), q.size());
            String[] arr = q.toArray(new String[0]);
            boolean first = true;
            for (int i = arr.length - n; i < arr.length; i++) {
                if (!first) sb.append(',');
                first = false;
                sb.append(arr[i]);
            }
        }
        sb.append("]}");
        return sb.toString();
    }

    private static long extractJsonLongField(String json, String field) {
        if (json == null || json.isBlank() || field == null || field.isBlank()) return 0L;
        String token = "\"" + field + "\":";
        int i = json.indexOf(token);
        if (i < 0) return 0L;
        int p = i + token.length();
        int n = json.length();
        while (p < n && Character.isWhitespace(json.charAt(p))) p++;
        int start = p;
        while (p < n) {
            char ch = json.charAt(p);
            if (ch >= '0' && ch <= '9') {
                p++;
                continue;
            }
            break;
        }
        if (p <= start) return 0L;
        try {
            return Long.parseLong(json.substring(start, p));
        } catch (NumberFormatException ignored) {
            return 0L;
        }
    }

