    private static String buildObserveTraceJson(String traceId, int limit) {
        String tid = traceId == null ? "" : traceId.trim();
        if (tid.isBlank()) {
            return "{\"traceId\":\"\",\"count\":0,\"items\":[]}";
        }
        List<String> lines = Collections.emptyList();
        try {
            if (Files.exists(OBSERVE_EVENTS_PATH)) {
                lines = Files.readAllLines(OBSERVE_EVENTS_PATH, StandardCharsets.UTF_8);
            }
        } catch (Exception ignored) {
            lines = Collections.emptyList();
        }
        StringBuilder arr = new StringBuilder();
        arr.append('[');
        int emitted = 0;
        for (int i = lines.size() - 1; i >= 0 && emitted < limit; i--) {
            String ln = lines.get(i);
            if (ln == null || ln.isBlank()) continue;
            if (!(ln.contains(tid)
                    || ln.contains("\"turnId\":\"" + tid + "\"")
                    || ln.contains("\"collapseEpisodeId\":\"" + tid + "\""))) {
                continue;
            }
            if (emitted > 0) arr.append(',');
            arr.append(ln);
            emitted++;
        }
        arr.append(']');
        return "{"
                + "\"traceId\":\""
                + SimplifiedJsonParser.escapeJson(tid)
                + "\",\"count\":"
                + emitted
                + ",\"items\":"
                + arr
                + "}";
    }

