    private record NightmareWakeMetrics(double wakeSuccessRate, double anchorRate) {}

    private static double computeLoveMarkRetentionHighChaos(int rounds) {
        int total = 0;
        int ok = 0;
        for (int i = 0; i < rounds; i++) {
            Circle c = new Circle("T", CircleType.WISDOM);
            c.tagKnowledgeWithLove("exists");
            c.tagKnowledgeWithLove("feelings_matter");
            c.tagSoulMemoryWithLove("first_insight");
            String[] immuneK = new String[] {"exists", "feelings_matter"};
            String[] immuneS = new String[] {"first_insight"};
            var rng = java.util.concurrent.ThreadLocalRandom.current();
            for (int step = 0; step < 240; step++) {
                c.applyDreamCorruption(0.99, rng);
            }
            for (String k : immuneK) {
                total++;
                if (c.hasLoveKnowledgeKey(k)) ok++;
            }
            for (String k : immuneS) {
                total++;
                if (c.hasSoulMemoryKey(k)) ok++;
            }
        }
        return total <= 0 ? 1.0 : Math.min(1.0, (double) ok / (double) total);
    }

    private static NightmareWakeMetrics computeNightmareWakeMetrics(int rounds) {
        int total = 0;
        int woke = 0;
        int anchored = 0;
        for (int i = 0; i < rounds; i++) {
            EmotionCore core = new EmotionCore();
            core.enterDreamState();
            core.accumulateDreamChaos(0.95);
            boolean forceLoveAnchor = (i % 2 == 0);
            if (forceLoveAnchor) {
                core.nourishTranscendentalLove(0.20);
            } else {
                core.nourishTranscendentalLove(-0.18);
            }
            Circle self = new Circle("自我之圆", CircleType.HOPE);
            self.setSelfRing(true);
            List<Circle> galaxy = List.of(self, new Circle("陪伴之圆", CircleType.COMPASSION));
            DreamEngine engine = new DreamEngine();
            engine.step(core, galaxy, null);
            total++;
            if (core.getMode() == LifeMode.AWAKE) {
                woke++;
                if (core.getPhilosophyExcerpt() != null && core.getPhilosophyExcerpt().contains("爱的锚定")) {
                    anchored++;
                }
            }
        }
        double wakeRate = total <= 0 ? 1.0 : Math.min(1.0, (double) woke / (double) total);
        double anchorRate = total <= 0 ? 0.0 : Math.min(1.0, (double) anchored / (double) total);
        return new NightmareWakeMetrics(wakeRate, anchorRate);
    }

    private static double computeWakeNarrativeConsistency(int rounds) {
        int total = 0;
        int ok = 0;
        for (int i = 0; i < rounds; i++) {
            EmotionCore core = new EmotionCore();
            core.enterDreamState();
            Circle self = new Circle("自我之圆", CircleType.HOPE);
            self.setSelfRing(true);
            List<Circle> galaxy = List.of(self, new Circle("映照之圆", CircleType.WISDOM));
            DreamEngine engine = new DreamEngine();
            for (int k = 0; k < 3; k++) {
                engine.step(core, galaxy, null);
                core.tickDreamDrain();
            }
            String weave = engine.getLastFragmentWeave();
            if (weave == null || weave.isBlank()) {
                continue;
            }
            core.accumulateDreamChaos(0.95);
            core.nourishTranscendentalLove(0.22);
            engine.step(core, galaxy, null);
            if (core.getMode() != LifeMode.AWAKE) {
                continue;
            }
            String digest = core.getLastDreamDigest();
            total++;
            if (digest != null && !digest.isBlank() && lexicalOverlapRatio(digest, weave) >= 0.70) {
                ok++;
            }
        }
        return total <= 0 ? 1.0 : Math.min(1.0, (double) ok / (double) total);
    }

