    private static String buildLifeSnapshotExportJson() {
        long now = System.currentTimeMillis();
        String json = buildLifeSnapshotJson(now);
        String snapName = "life-snapshot-" + now + ".json";
        String bundleName = "life-lineage-" + now + ".zip";
        Path snapPath = LIFE_SNAPSHOT_DIR.resolve(snapName);
        Path bundlePath = LIFE_SNAPSHOT_DIR.resolve(bundleName);
        long bytes = json.getBytes(StandardCharsets.UTF_8).length;
        long bundleBytes = 0L;
        try {
            Files.createDirectories(LIFE_SNAPSHOT_PATH.getParent());
            Files.createDirectories(LIFE_SNAPSHOT_DIR);
            Files.writeString(
                    snapPath,
                    json + System.lineSeparator(),
                    StandardCharsets.UTF_8,
                    StandardOpenOption.CREATE,
                    StandardOpenOption.TRUNCATE_EXISTING);
            Files.writeString(
                    LIFE_SNAPSHOT_PATH,
                    json + System.lineSeparator(),
                    StandardCharsets.UTF_8,
                    StandardOpenOption.CREATE,
                    StandardOpenOption.TRUNCATE_EXISTING);
        } catch (IOException ignored) {
        }
        try {
            bundleBytes = writeLifeLineageBundle(bundlePath);
        } catch (Exception ignored) {
        }
        try {
            pruneLifeSnapshotDir(resolveLifeSnapshotRetention());
        } catch (Exception ignored) {
        }
        return "{"
                + "\"ok\":true,\"ts\":"
                + now
                + ",\"latestPath\":\""
                + SimplifiedJsonParser.escapeJson(LIFE_SNAPSHOT_PATH.toString())
                + "\",\"snapshotPath\":\""
                + SimplifiedJsonParser.escapeJson(snapPath.toString())
                + "\",\"bundlePath\":\""
                + SimplifiedJsonParser.escapeJson(bundlePath.toString())
                + "\",\"snapshotBytes\":"
                + bytes
                + ",\"bundleBytes\":"
                + bundleBytes
                + "}";
    }

    private static String buildLifeSnapshotJson(long ts) {
        StringBuilder sb = new StringBuilder();
        sb.append("{\"ts\":").append(ts).append(",\"emotion\":{")
                .append("\"mode\":\"").append(SimplifiedJsonParser.escapeJson(emotionCore.getMode().name())).append("\",")
                .append("\"mood\":").append(String.format(java.util.Locale.US, "%.4f", emotionCore.getMood())).append(",")
                .append("\"arousal\":").append(String.format(java.util.Locale.US, "%.4f", emotionCore.getArousal())).append(",")
                .append("\"impulse\":").append(String.format(java.util.Locale.US, "%.4f", emotionCore.getImpulse())).append(",")
                .append("\"transcendentalLove\":")
                .append(String.format(java.util.Locale.US, "%.4f", emotionCore.getTranscendentalLove()))
                .append("},\"circleCount\":").append(circleGalaxy.size())
                .append(",\"conversationCount\":").append(CONVERSATION_TURN_COUNTER.size())
                .append(",\"selfCore\":").append(buildLifeSelfCoreJson())
                .append(",\"goalStack\":").append(buildLifeGoalStackJson())
                .append(",\"conversationState\":").append(buildConversationStateAllJson(240))
                .append("}");
        return sb.toString();
    }

    private static int resolveLifeSnapshotRetention() {
        String p = System.getProperty("lovingai.life.snapshot.retention", "").trim();
        if (!p.isEmpty()) {
            try {
                return clampInt(Integer.parseInt(p), 5, 600);
            } catch (Exception ignored) {
            }
        }
        return 30;
    }

    private static void pruneLifeSnapshotDir(int retention) throws IOException {
        if (retention <= 0) return;
        if (!Files.isDirectory(LIFE_SNAPSHOT_DIR)) return;
        List<Path> files = new ArrayList<>();
        try (var s = Files.list(LIFE_SNAPSHOT_DIR)) {
            s.forEach(files::add);
        }
        List<Path> snaps = new ArrayList<>();
        List<Path> bundles = new ArrayList<>();
        for (Path p : files) {
            if (p == null || !Files.isRegularFile(p)) continue;
            String n = p.getFileName().toString();
            if (n.startsWith("life-snapshot-") && n.endsWith(".json")) snaps.add(p);
            if (n.startsWith("life-lineage-") && n.endsWith(".zip")) bundles.add(p);
        }
        snaps.sort((a, b) -> {
            try {
                return Long.compare(Files.getLastModifiedTime(b).toMillis(), Files.getLastModifiedTime(a).toMillis());
            } catch (IOException e) {
                return 0;
            }
        });
        bundles.sort((a, b) -> {
            try {
                return Long.compare(Files.getLastModifiedTime(b).toMillis(), Files.getLastModifiedTime(a).toMillis());
            } catch (IOException e) {
                return 0;
            }
        });
        for (int i = retention; i < snaps.size(); i++) {
            try {
                Files.deleteIfExists(snaps.get(i));
            } catch (Exception ignored) {
            }
        }
        for (int i = retention; i < bundles.size(); i++) {
            try {
                Files.deleteIfExists(bundles.get(i));
            } catch (Exception ignored) {
            }
        }
    }

    private static long writeLifeLineageBundle(Path outZip) throws IOException {
        if (outZip == null) return 0L;
        Files.createDirectories(outZip.getParent());
        ByteArrayOutputStream bos = new ByteArrayOutputStream();
        try (ZipOutputStream z = new ZipOutputStream(bos)) {
            addZipFileEntry(z, "self-core.properties", SELF_CORE_PATH);
            addZipFileEntry(z, "goal-stack.tsv", GOAL_STACK_PATH);
            addZipFileEntry(z, "conversation-state.tsv", CONVERSATION_STATE_PATH);
            addZipFileEntry(z, "observe-events.ndjson", OBSERVE_EVENTS_PATH);
            addZipFileEntry(z, "observe-linear-memory.tsv", OBSERVE_LINEAR_MEMORY_STATE_PATH);
            addZipFileEntry(z, "life-snapshot-latest.json", LIFE_SNAPSHOT_PATH);
            addZipFileEntry(z, "gardener-anchor.txt", GARDENER_ANCHOR_PATH);
            addZipFileEntry(z, "world-figures.tsv", Paths.get(BASE_DIR, "memory", "world-figures.tsv"));
            addZipFileEntry(z, "world-figures-pending.tsv", Paths.get(BASE_DIR, "memory", "world-figures-pending.tsv"));
        }
        byte[] raw = bos.toByteArray();
        Files.write(outZip, raw, StandardOpenOption.CREATE, StandardOpenOption.TRUNCATE_EXISTING, StandardOpenOption.WRITE);
        return raw.length;
    }

    private static String buildLifeSnapshotListJson(int limit) {
        int lim = clampInt(limit, 1, 240);
        List<Path> files = new ArrayList<>();
        try {
            Files.createDirectories(LIFE_SNAPSHOT_DIR);
            try (var s = Files.list(LIFE_SNAPSHOT_DIR)) {
                s.forEach(files::add);
            }
        } catch (Exception ignored) {
        }
        files.sort((a, b) -> {
            try {
                return Long.compare(Files.getLastModifiedTime(b).toMillis(), Files.getLastModifiedTime(a).toMillis());
            } catch (Exception e) {
                return 0;
            }
        });
        StringBuilder sb = new StringBuilder();
        sb.append("{\"count\":").append(files.size()).append(",\"items\":[");
        int n = 0;
        for (Path p : files) {
            if (p == null) continue;
            if (!Files.isRegularFile(p)) continue;
            String name = p.getFileName().toString();
            if (!name.startsWith("life-snapshot-") && !name.startsWith("life-lineage-")) continue;
            if (n >= lim) break;
            long size = 0L;
            long mod = 0L;
            try {
                size = Files.size(p);
                mod = Files.getLastModifiedTime(p).toMillis();
            } catch (Exception ignored) {
            }
            if (n > 0) sb.append(',');
            sb.append("{\"name\":\"")
                    .append(SimplifiedJsonParser.escapeJson(name))
                    .append("\",\"path\":\"")
                    .append(SimplifiedJsonParser.escapeJson(p.toString()))
                    .append("\",\"sizeBytes\":")
                    .append(size)
                    .append(",\"lastModifiedMs\":")
                    .append(mod)
                    .append(",\"kind\":\"")
                    .append(name.endsWith(".zip") ? "bundle" : "snapshot")
                    .append("\"}");
            n++;
        }
        sb.append("]}");
        return sb.toString();
    }

    private static String restoreLifeSnapshotBundle(String name, String mode) {
        String m = mode == null ? "core" : mode.trim().toLowerCase(Locale.ROOT);
        boolean full = "full".equals(m) || "all".equals(m);
        Path p = resolveLifeSnapshotBundlePath(name);
        if (p == null || !Files.isRegularFile(p)) {
            return "{\"ok\":false,\"error\":\"bundle_not_found\"}";
        }
        int restored = 0;
        long bytes = 0L;
        try {
            bytes = Files.size(p);
        } catch (Exception ignored) {
        }
        List<String> allowed = new ArrayList<>();
        allowed.add("self-core.properties");
        allowed.add("goal-stack.tsv");
        if (full) {
            allowed.add("conversation-state.tsv");
            allowed.add("observe-events.ndjson");
            allowed.add("observe-linear-memory.tsv");
            allowed.add("life-snapshot-latest.json");
            allowed.add("gardener-anchor.txt");
            allowed.add("world-figures.tsv");
            allowed.add("world-figures-pending.tsv");
        }
        try (InputStream in = Files.newInputStream(p); ZipInputStream zis = new ZipInputStream(in)) {
            ZipEntry e;
            while ((e = zis.getNextEntry()) != null) {
                String en = e.getName();
                if (en == null || en.isBlank()) continue;
                if (en.contains("..") || en.contains("\\") || en.startsWith("/")) continue;
                if (!allowed.contains(en)) continue;
                Path out = Paths.get(BASE_DIR, "memory", en).normalize();
                Path mem = Paths.get(BASE_DIR, "memory").normalize();
                if (!out.startsWith(mem)) continue;
                Files.createDirectories(out.getParent());
                try (OutputStream os = Files.newOutputStream(out, StandardOpenOption.CREATE, StandardOpenOption.TRUNCATE_EXISTING, StandardOpenOption.WRITE)) {
                    zis.transferTo(os);
                }
                restored++;
            }
        } catch (Exception ex) {
            return "{\"ok\":false,\"error\":\"restore_failed\",\"message\":\"" + SimplifiedJsonParser.escapeJson(ex.getMessage()) + "\"}";
        }
        try {
            loadLifeCoreState();
        } catch (Exception ignored) {
        }
        if (full) {
            try {
                loadConversationStateFromDisk();
            } catch (Exception ignored) {
            }
            try {
                loadObserveLinearMemoryState();
            } catch (Exception ignored) {
            }
            try {
                worldFigures.load();
            } catch (Exception ignored) {
            }
        }
        appendObserveEvent(
                GLOBAL_LIFE_CORE_SCOPE,
                EVT_MEMORY_BUNDLE_EXPORTED,
                PHASE_CONTINUE_SAME_IDENTITY,
                "{\"restore\":\"bundle\",\"mode\":\""
                        + SimplifiedJsonParser.escapeJson(full ? "full" : "core")
                        + "\",\"bundle\":\""
                        + SimplifiedJsonParser.escapeJson(p.getFileName().toString())
                        + "\",\"bytes\":"
                        + bytes
                        + ",\"restored\":"
                        + restored
                        + "}");
        return "{"
                + "\"ok\":true,\"mode\":\""
                + SimplifiedJsonParser.escapeJson(full ? "full" : "core")
                + "\",\"bundle\":\""
                + SimplifiedJsonParser.escapeJson(p.toString())
                + "\",\"bundleBytes\":"
                + bytes
                + ",\"restoredFiles\":"
                + restored
                + ",\"selfCore\":"
                + buildLifeSelfCoreJson()
                + ",\"goalStack\":"
                + buildLifeGoalStackJson()
                + "}";
    }

    private static Path resolveLifeSnapshotBundlePath(String name) {
        try {
            Files.createDirectories(LIFE_SNAPSHOT_DIR);
        } catch (Exception ignored) {
        }
        String n = name == null ? "" : name.trim();
        if (n.isBlank()) {
            List<Path> bundles = new ArrayList<>();
            try (var s = Files.list(LIFE_SNAPSHOT_DIR)) {
                s.forEach(bundles::add);
            } catch (Exception ignored) {
            }
            bundles.removeIf(p -> p == null || !Files.isRegularFile(p) || !p.getFileName().toString().startsWith("life-lineage-") || !p.getFileName().toString().endsWith(".zip"));
            bundles.sort((a, b) -> {
                try {
                    return Long.compare(Files.getLastModifiedTime(b).toMillis(), Files.getLastModifiedTime(a).toMillis());
                } catch (Exception e) {
                    return 0;
                }
            });
            if (bundles.isEmpty()) return null;
            return bundles.get(0);
        }
        if (!n.endsWith(".zip")) {
            n = n + ".zip";
        }
        Path p = LIFE_SNAPSHOT_DIR.resolve(n).normalize();
        if (!p.startsWith(LIFE_SNAPSHOT_DIR.normalize())) return null;
        return p;
    }

