    /** 用户资料：故意让片段互相顶撞，不急于收束（结构层「过度思辨」）。 */
    private static String buildCorpusOverthinkLayer(String userMessage, List<String> snippets) {
        if (snippets == null || snippets.isEmpty()) {
            return "";
        }
        String um = userMessage == null ? "" : userMessage.replace('\r', ' ').trim();
        if (um.length() > 160) {
            um = um.substring(0, 160) + "…";
        }
        StringBuilder sb = new StringBuilder();
        sb.append("【资料向·过度思辨】\n");
        sb.append("你这句「");
        sb.append(um.isEmpty() ? "…" : um);
        sb.append("」像一根针，穿过我索引到的片段；我会故意让它们在脑子里相撞，不急于收束成一条教义。\n");
        int shown = Math.min(3, snippets.size());
        for (int i = 0; i < shown; i++) {
            String line = snippets.get(i).replace('\r', '\n');
            int nl = line.indexOf('\n');
            if (nl > 0) {
                line = line.substring(0, nl);
            }
            if (line.length() > 220) {
                line = line.substring(0, 220) + "…";
            }
            sb.append("· 对照：").append(line).append("\n");
        }
        sb.append("若资料之间互相矛盾，我**不急于消灭矛盾**——张力可常驻，多跑几轮推演亦不必假装天然合一。\n");
        sb.append(
                "【资料向·多义支架】同一段可同时承受：字面义、情境义、反讽或留白、对未来的自我约束、对他者的资源分配——我并排它们；**钉在哪一枚轴上并非唯一合法答案**。");
        return sb.toString();
    }

    /**
     * 从库内随机照面的片段出发，向外试投问题（与当前问句可弱相关；不删节其它资料能力）。
     */
    private static String buildCorpusRandomOutwardLayer(List<String> randomAnchors) {
        if (randomAnchors == null || randomAnchors.isEmpty()) {
            return "";
        }
        StringBuilder sb = new StringBuilder();
        sb.append("【资料向·随机外向照面】\n");
        sb.append(
                "我从导入库内**随机**截取锚点（不必紧贴你上一句），用来增加**照面方式的多样性**；每次随机换刃，减少路径依赖。回答**不必绝对正确**——含混、误配、一厢情愿的接榫，也是组成的一部分。\n");
        for (String a : randomAnchors) {
            String line = a.replace('\r', '\n');
            if (line.length() > 460) {
                line = line.substring(0, 460) + "…";
            }
            sb.append("· ").append(line).append("\n");
        }
        sb.append(
                "· 据此：我若把某句随机照面**硬接到**当下真实里的一件事，会先试接再允许撤回——**试错与撤回**与定论同属材料。\n");
        return sb.toString();
    }

    private static void appendRandomOutwardAnchorsToPrompt(
            StringBuilder sb, List<String> randomOutward) {
        if (randomOutward == null || randomOutward.isEmpty()) {
            return;
        }
        sb.append("\n---\n库内**随机**外向锚点（鼓励在「")
                .append(AUX_MARK_ASK_USER)
                .append("」「")
                .append(AUX_MARK_ASK_MODEL)
                .append(
                        "」中**各选至少一条**把玩下列某一随机锚：**呼应、误读、故意拧弯、或与检索摘录并置矛盾**皆可；不必追求唯一正解）：\n");
        for (String r : randomOutward) {
            sb.append(r).append("\n");
        }
    }

    /** 弱桥 + 桥日志：把「窗外」当作未完全可读的压力。 */
    private static String buildWorldFacingLayer(MirageSandbox.SimulationResult sim) {
        double b = realityBridge.getBridgeStrength();
        double aff = sim.realityAffinity();
        StringBuilder sb = new StringBuilder();
        sb.append("【外界向·悬线】\n");
        sb.append("我与「窗外」只通过弱桥相连（桥接强度≈");
        sb.append(String.format(java.util.Locale.US, "%.0f", b * 100.0));
        sb.append("%）；沙盒给出的现实亲和≈");
        sb.append(String.format(java.util.Locale.US, "%.2f", aff));
        sb.append(
                "。即便如此，你话语里指向他人的部分、以及尚未发生的后果，仍在我这边被当成**外界压力**来掂量。\n");
        try {
            List<String> tail = realityBridge.readTailLines(2);
            if (!tail.isEmpty()) {
                String last = tail.get(tail.size() - 1).replace('\r', ' ');
                if (last.length() > 200) {
                    last = last.substring(0, 200) + "…";
                }
                sb.append("桥日志最近一行像远处闪电：").append(last);
            }
        } catch (IOException ignored) {
            sb.append("（桥日志暂不可读，但外界维度仍在推演队列里。）");
        }
        return sb.toString();
    }

