    private static AuxLlmSplit ensureAuxQuestions(
            AuxLlmSplit raw,
            String message,
            MirageSandbox.SimulationResult sim,
            List<String> snippets,
            List<String> randomOutward) {
        if (raw == null) {
            raw = new AuxLlmSplit("", "", "");
        }
        String askUser =
                (raw.askUser() == null || raw.askUser().isBlank())
                        ? fallbackAskUserBlock(message, sim, snippets, randomOutward)
                        : raw.askUser().trim();
        String askModel =
                (raw.askModel() == null || raw.askModel().isBlank())
                        ? fallbackAskModelBlock(message, sim, snippets, randomOutward)
                        : raw.askModel().trim();
        return new AuxLlmSplit(raw.main(), askUser, askModel);
    }

    /** 未开本地模型时追加一层与用户相接的声部（自述与问句混排，不替代镜像主声）。 */
