        var rng = ThreadLocalRandom.current();
        StringBuilder sb = new StringBuilder();
        sb.append("\n\n【内生接续·与你相接】\n");
        sb.append("（我从自身节律、沙盒刻度与**圆/梦存储**出发；以下混排陈述、暂缓、邀请与偶有问句——不是审讯清单。）\n");
