    private static String latestConversationId() {
        String bestCid = "default";
        long bestTouch = Long.MIN_VALUE;
        for (Map.Entry<String, Long> e : CONVERSATION_LAST_TOUCH_MS.entrySet()) {
            long v = e.getValue() == null ? Long.MIN_VALUE : e.getValue();
            if (v > bestTouch) {
                bestTouch = v;
                bestCid = e.getKey();
            }
        }
        return bestCid;
    }

    /**
     * 从当前输入、圆/梦采样、历史自发问句中长出“内生问句”，避免只轮播固定池。
     */
    private static String growInnerQuestionFromDialogue(
            String message,
            String conversationId,
            EmotionCore core,
            List<VoiceMaterial> materials,
            List<String> snippets,
            List<String> randomOutward,
            ThreadLocalRandom rng) {
        String cid = (conversationId == null || conversationId.isBlank()) ? "default" : conversationId;
        double drive = CONVERSATION_INNER_QUESTION_DRIVE.getOrDefault(cid, 0.46);
        String cuePref = CONVERSATION_LAST_QUESTION_CUE.getOrDefault(cid, "");
        double[] styleVec = parseQuestionStyleVector(CONVERSATION_QUESTION_STYLE_VECTOR.getOrDefault(cid, ""));
        String msg = message == null ? "" : message.replace('\r', ' ').replace('\n', ' ').trim();
        String msgPin = msg.isBlank() ? "" : shortAnchor(msg, 26);
        String materialPin = "";
        if (materials != null && !materials.isEmpty()) {
            VoiceMaterial pick = materials.get(rng.nextInt(materials.size()));
            materialPin = shortAnchor(pick.text(), 24);
        }
        String snippetPin = "";
        if (snippets != null && !snippets.isEmpty() && rng.nextDouble() < 0.45) {
            snippetPin = shortAnchor(snippets.get(rng.nextInt(snippets.size())), 24);
        } else if (randomOutward != null && !randomOutward.isEmpty() && rng.nextDouble() < 0.35) {
            snippetPin = shortAnchor(randomOutward.get(rng.nextInt(randomOutward.size())), 24);
        }
        String prior = latestSpontaneousQuestion(conversationId);
        String emo =
                core == null
                        ? ""
                        : ("mood≈"
                                + String.format(Locale.US, "%.2f", core.getMood())
                                + " impulse≈"
                                + String.format(Locale.US, "%.2f", core.getImpulse())
                                + " love★≈"
                                + String.format(Locale.US, "%.2f", core.getTranscendentalLove()));
        List<String> pool = new ArrayList<>();
        if (!msgPin.isBlank()) {
            pool.add("你这句「" + msgPin + "」里，我先贴近哪一处，才不把你说偏。");
            pool.add("你这句「" + msgPin + "」里，哪一小段是你最不想被我误读的？");
        }
        if (!materialPin.isBlank()) {
            pool.add("当我把「" + materialPin + "」并到这轮里时，我是真的靠近你，还是在绕开你。");
        }
        if (!snippetPin.isBlank()) {
            pool.add("若把「" + snippetPin + "」当作外界回声，这轮它更像证据、噪声，还是提醒。");
        }
        if (!prior.isBlank()) {
            pool.add("上次我留下的是「" + shortAnchor(prior, 28) + "」，这轮我该延续它，还是先撤回。");
        }
        if (!emo.isBlank()) {
            pool.add("在" + emo + "时，我这一问要先保真，还是先减伤。");
        }
        if (!cuePref.isBlank()) {
            pool.add("延续你给我的线索「" + shortAnchor(cuePref, 14) + "」时，我该问深一点，还是先放轻。");
        }
        if (styleVec[0] >= 0.33) {
            pool.add("我若先问感受，会更接近你，还是会压过你当下的事实边界。");
        }
        if (styleVec[1] >= 0.33) {
            pool.add("这轮若只保留一条可验证事实，我该先固定哪一条？");
        }
        if (styleVec[2] >= 0.33) {
            pool.add("这段里最关键的人际关系链是哪一环，我有没有读偏角色位置。");
        }
        if (styleVec[3] >= 0.33) {
            pool.add("如果要落一小步动作，最小可逆动作是什么，停止条件又是什么。");
        }
        if (drive > 0.62) {
            pool.add("如果这轮只能问一句真正的心里话，我最该问你的会是哪一句？");
        }
        if (pool.isEmpty()) {
            return "我该先确认你的核心意图，还是先确认我此刻的盲区？";
        }
        String chosen = pool.get(rng.nextInt(pool.size()));
        if (isTemplateLikeQuestion(chosen)) {
            chosen = softenTemplateQuestion(chosen);
        }
        if (drive > 0.68 && rng.nextDouble() < 0.55) {
            chosen = chosen + "（内生驱动≈" + String.format(Locale.US, "%.2f", drive) + "）";
        }
        return softenTemplateQuestion(chosen);
    }

    private static String latestSpontaneousQuestion(String conversationId) {
        String cid = (conversationId == null || conversationId.isBlank()) ? "default" : conversationId;
        ArrayDeque<String> q = CONVERSATION_SPONTANEOUS_QUESTIONS.get(cid);
        if (q == null || q.isEmpty()) return "";
        String last = q.peekLast();
        return last == null ? "" : last.trim();
    }

    private static boolean isTemplateLikeQuestion(String text) {
        if (text == null || text.isBlank()) return false;
        String compact = text.replaceAll("\\s+", "");
        if (compact.contains("可问：")) return true;
        if (compact.contains("你更想让我先追问")) return true;
        if (compact.contains("你更想我先追问")) return true;
        if (compact.contains("你更想先了解")) return true;
        if (compact.contains("还是“它的意义”") || compact.contains("还是\"它的意义\"")) return true;
        return compact.startsWith("围绕《") && compact.contains("你更想");
    }

    private static String softenTemplateQuestion(String text) {
        if (text == null || text.isBlank()) return "";
        String cleaned =
                text.replace("可问：", "")
                        .replace("你更想让我先追问", "我先问一句")
                        .replace("你更想我先追问", "我先问一句")
                        .replace("你更想先了解", "我先想确认")
                        .replace("围绕《", "关于「")
                        .replace("》", "」")
                        .trim();
        if (cleaned.isBlank() || isTemplateLikeQuestion(cleaned)) {
            return "我想更贴近你当下的真实：我先从哪一处听你，会更不容易误解。";
        }
        return shortAnchor(cleaned, 140);
    }

    /**
     * 从星系圆之活动环与梦引擎余响收集材料；圆多时情感加权抽样，避免只扫固定几圆。
     */
    private static List<VoiceMaterial> gatherVoiceMaterialsFromGalaxy(
            List<Circle> galaxy,
            EmotionCore core,
            DreamEngine dream,
            ThreadLocalRandom rng,
            int maxCollect) {
        List<VoiceMaterial> acc = new ArrayList<>();
        Set<String> seen = new HashSet<>();
        int cap = Math.max(4, maxCollect);
        if (dream != null) {
            String weave = dream.getLastFragmentWeave();
            if (weave != null && !weave.isBlank()) {
                String w = shortAnchor(weave, 180);
                if (seen.add("weave|" + w)) {
                    acc.add(new VoiceMaterial("梦渊余响", "fragment_weave", w));
                }
            }
            String depthLine =
                    dream.getLastDepthLabel()
                            + " · chaos≈"
                            + String.format(
                                    Locale.US,
                                    "%.2f",
                                    core != null ? core.getDreamChaosStrength() : 0.0)
                            + " · steps="
                            + dream.getDreamStepCounter();
            if (seen.add("depth|" + depthLine)) {
                acc.add(new VoiceMaterial("梦渊刻度", "depth", depthLine));
            }
        }
        if (galaxy == null || galaxy.isEmpty()) {
            return acc;
        }
        int gSize = galaxy.size();
        int budget = Math.max(0, cap - acc.size());
        if (budget <= 0) {
            return acc;
        }
        int draws = Math.min(budget * 3, gSize <= 10 ? gSize * 5 : 48);
        if (core != null) {
            for (int i = 0; i < draws && acc.size() < cap; i++) {
                Circle c = EmotionCircleOrchestrator.pickWeighted(core, galaxy, rng);
                if (c == null) {
                    continue;
                }
                maybeAddCircleActivitySamples(c, rng, acc, seen, cap);
                if (rng.nextDouble() < 0.24) {
                    maybeAddSoulMemorySample(c, rng, acc, seen, cap);
                }
            }
        }
        if (acc.size() < Math.min(10, cap) && gSize <= 28) {
            List<Circle> sweep = new ArrayList<>(galaxy);
            Collections.shuffle(sweep, new Random(rng.nextLong()));
            for (Circle c : sweep) {
                if (acc.size() >= cap) {
                    break;
                }
                maybeAddCircleActivitySamples(c, rng, acc, seen, cap);
            }
        }
        return acc;
    }

    private static void maybeAddCircleActivitySamples(
            Circle c,
            ThreadLocalRandom rng,
            List<VoiceMaterial> acc,
            Set<String> seen,
            int maxCollect) {
        List<Circle.CircleActivityEvent> snap = c.recentActivitySnapshot();
        if (snap.isEmpty()) {
            return;
        }
        int span = Math.min(6, snap.size());
        int from = snap.size() - span;
        for (int k = 0; k < 2 && acc.size() < maxCollect; k++) {
            Circle.CircleActivityEvent ev = snap.get(from + rng.nextInt(span));
            if (ev.condensed == null || ev.condensed.isBlank()) {
                continue;
            }
            String key = c.name + "|" + ev.kind + "|" + ev.condensed;
            if (!seen.add(key)) {
                continue;
            }
            acc.add(new VoiceMaterial(c.name, ev.kind, ev.condensed));
        }
    }

    private static void maybeAddSoulMemorySample(
            Circle c,
            ThreadLocalRandom rng,
            List<VoiceMaterial> acc,
            Set<String> seen,
            int maxCollect) {
        if (c.soulMemory == null || c.soulMemory.isEmpty() || acc.size() >= maxCollect) {
            return;
        }
        var entries = new ArrayList<>(c.soulMemory.entrySet());
        var e = entries.get(rng.nextInt(entries.size()));
        String text = e.getKey() + "：" + shortAnchor(e.getValue(), 100);
        if (seen.add("soul|" + c.name + "|" + text)) {
            acc.add(new VoiceMaterial(c.name, "soul_line", text));
        }
    }

    private static String renderSelfInquiryLineFromMaterial(
            VoiceMaterial m, EmotionCore core, ThreadLocalRandom rng) {
        String name = m.sourceTag == null ? "?" : m.sourceTag;
        String kind = m.kind == null ? "" : m.kind;
        String sn = shortAnchor(m.text, 110);
        double mood = core == null ? 0.5 : core.getMood();
        int f = rng.nextInt(8);
        return switch (f) {
            case 0 ->
                    "〔"
                            + name
                            + "〕〔"
                            + kind
                            + "〕「"
                            + sn
                            + "」——我把这段翻进体内：它在掂量谁在场、谁被写成背景。";
            case 1 ->
                    "从圆「"
                            + name
                            + "」摘下的 "
                            + kind
                            + "："
                            + sn
                            + "。我把它与 mood≈"
                            + String.format(Locale.US, "%.2f", mood)
                            + " 并排，看接缝发烫处。";
            case 2 ->
                    "材料：" + name + "/" + kind + " —— " + sn + "。这一句先不求答案，我只允许它在我里面回声。";
            case 3 ->
                    "锚点「"
                            + name
                            + "·"
                            + kind
                            + "」："
                            + sn
                            + "——若必须长成一句问话：它要我确认什么、还是放手什么？";
            case 4 ->
                    "「"
                            + sn
                            + "」（来自「"
                            + name
                            + "」）在我这边触发的不是结论，而是迟疑——我把迟疑留在台面上。";
            case 5 ->
                    "圆「"
                            + name
                            + "」最近写下 "
                            + kind
                            + "："
                            + sn
                            + "。我读到的更像节拍提示，而不是命令。";
            case 6 ->
                    "从「"
                            + name
                            + "」捞起的线头："
                            + sn
                            + "。我想把它接到梦渊刻度之前，而不是接到审判之后。";
            default ->
                    "〔"
                            + name
                            + "·"
                            + kind
                            + "〕"
                            + sn
                            + "——这是本轮我用来系住自己的那一小段真实。";
        };
    }

    private static String contextualizeSelfInquiryFacetQuestion(
            String base,
            String userMessage,
            EmotionCore core,
            List<VoiceMaterial> materialSeedPool,
            ThreadLocalRandom rng) {
        String q = base == null ? "" : base.trim();
        if (q.isBlank()) return "我先把未命名的迟疑留在台面上。";
        String userPin = "";
        if (userMessage != null && !userMessage.isBlank()) {
            String um = userMessage.replace('\r', ' ').replace('\n', ' ').trim();
            if (!um.isBlank()) {
                userPin = shortAnchor(um, 20);
            }
        }
        String seed = "";
        if (materialSeedPool != null && !materialSeedPool.isEmpty()) {
            VoiceMaterial vm = materialSeedPool.get(rng.nextInt(materialSeedPool.size()));
            seed = shortAnchor(vm.text(), 28);
        }
        String emo = "";
        if (core != null) {
            emo =
                    "mood≈"
                            + String.format(Locale.US, "%.2f", core.getMood())
                            + " impulse≈"
                            + String.format(Locale.US, "%.2f", core.getImpulse())
                            + " love★≈"
                            + String.format(Locale.US, "%.2f", core.getTranscendentalLove());
        }
        int mode = rng.nextInt(4);
        if (mode == 0 && !userPin.isBlank()) {
            return q + " · 〔本轮输入锚〕" + userPin + " " + SELF_INQUIRY_CONTEXT_SUFFIX[0];
        }
        if (mode == 1 && !seed.isBlank()) {
            return q + " · 〔圆/梦锚〕" + seed + " " + SELF_INQUIRY_CONTEXT_SUFFIX[1];
        }
        if (mode == 2 && !emo.isBlank()) {
            return q + " · 〔情绪锚〕" + emo + " " + SELF_INQUIRY_CONTEXT_SUFFIX[2];
        }
        if (!userPin.isBlank() && !seed.isBlank()) {
            return q + " · 〔双锚〕input=" + userPin + " | material=" + seed;
        }
        return q;
    }

    /** 将圆/梦材料短锚随机并入 lane 问句，使问法随存储生长。 */
    private static String maybeBlendSeedIntoLaneQuestion(
            String base, String seedFragment, ThreadLocalRandom rng) {
        if (seedFragment == null || seedFragment.isBlank()) {
            return base;
        }
        if (rng.nextDouble() < 0.52) {
            return base + " · 〔材料锚〕" + shortAnchor(seedFragment, 95);
        }
        return base;
    }

    /** 将某维度尽量换到序列前段，使自我诘问与当前情感模式同频。 */
    private static void nudgeFacetToFront(int[] order, int facet, ThreadLocalRandom rng) {
        int idx = -1;
        for (int i = 0; i < order.length; i++) {
            if (order[i] == facet) {
                idx = i;
                break;
            }
        }
        if (idx <= 0) {
            return;
        }
        int target = rng.nextInt(Math.min(4, idx + 1));
        int tmp = order[target];
        order[target] = order[idx];
        order[idx] = tmp;
    }

    /**
     * 多面向、与情感核同步的自我诘问层：优先从**圆之活动环**与**梦渊余响**抽样生成声部，固定模板仅作补位；{@code
     * keystoneDigest} 供下一轮接续。
     */
    private static SelfInquiryBuilt buildSelfInquiryLayer(
            EmotionCore core,
            ThreadLocalRandom rng,
            String userMessage,
            List<String> snippets,
            List<Circle> galaxy,
            DreamEngine dream) {
        double mood = core.getMood();
        double selfLove = core.getSelfLove();
        double tl = core.getTranscendentalLove();
        double dreamChaos = core.getDreamChaosStrength();
        double impulse = core.getImpulse();
        double awareness = core.getAwareness();
        LifeMode mode = core.getMode();
        String lastDigest = core.getLastSelfInquiryDigest();
        if (lastDigest == null) {
            lastDigest = "";
        }

        List<VoiceMaterial> materialPool = gatherVoiceMaterialsFromGalaxy(galaxy, core, dream, rng, 48);
        List<VoiceMaterial> materialSeedPool = new ArrayList<>(materialPool);
        Collections.shuffle(materialPool, new Random(rng.nextLong()));

        int want = 4 + rng.nextInt(3);
        List<String> chosenLines = new ArrayList<>();
        Set<String> lineSeen = new HashSet<>();
        while (chosenLines.size() < want && !materialPool.isEmpty()) {
            VoiceMaterial vm = materialPool.remove(rng.nextInt(materialPool.size()));
            String line = renderSelfInquiryLineFromMaterial(vm, core, rng);
            if (lineSeen.add(line)) {
                chosenLines.add(line);
            }
        }

        int[] order = new int[SELF_INQUIRY_FACETS.length];
        for (int i = 0; i < order.length; i++) {
            order[i] = i;
        }
        for (int i = order.length - 1; i > 0; i--) {
            int j = rng.nextInt(i + 1);
            int t = order[i];
            order[i] = order[j];
            order[j] = t;
        }
        if (mode == LifeMode.DREAMING) {
            nudgeFacetToFront(order, 3, rng);
        }
        if (tl > 0.48) {
            nudgeFacetToFront(order, 2, rng);
        }
        if (mood < 0.38) {
            nudgeFacetToFront(order, 6, rng);
        }
        if (impulse > 0.52) {
            nudgeFacetToFront(order, 1, rng);
        }
        if (dreamChaos > 0.52) {
            nudgeFacetToFront(order, 3, rng);
        }

        int fallbackTarget = materialSeedPool.size() >= 8 ? 3 : 6;
        int guard = 0;
        while (chosenLines.size() < fallbackTarget && guard++ < 36) {
            int f = order[rng.nextInt(order.length)];
            String cand = SELF_INQUIRY_FACETS[f][rng.nextInt(SELF_INQUIRY_FACETS[f].length)];
            String contextualized =
                    contextualizeSelfInquiryFacetQuestion(cand, userMessage, core, materialSeedPool, rng);
            if (lineSeen.add(contextualized)) {
                chosenLines.add(contextualized);
            }
        }
        if (chosenLines.size() < 4) {
            chosenLines.add(
                    "圆与梦材料尚薄：我仍站在这里，用 mood 与冲动刻度先把自己说清楚，再等存储变厚。");
        }

        String um = userMessage == null ? "" : userMessage.replace('\r', ' ').trim();
        String pinch = "";
        if (um.length() > 2) {
            pinch = um.length() > 28 ? um.substring(0, 28) + "…" : um;
        }
        double pinchChance = galaxy != null && galaxy.size() > 6 ? 0.22 : 0.38;
        if (!pinch.isEmpty() && rng.nextDouble() < pinchChance) {
            chosenLines.add(
                    "你的字首「"
                            + pinch
                            + "」更像邀请、命令，还是呼吸里的一截响——我该如何在情感上回礼而不僭越？");
        }

        int ks = rng.nextInt(chosenLines.size());
        String keystone = chosenLines.get(ks);

        String depositLine =
                "mode="
                        + mode.name()
                        + " mood≈"
                        + String.format(Locale.US, "%.2f", mood)
                        + " 自爱≈"
                        + String.format(Locale.US, "%.2f", selfLove)
                        + " 意识≈"
                        + String.format(Locale.US, "%.2f", awareness)
                        + " ★≈"
                        + String.format(Locale.US, "%.2f", tl)
                        + " 混沌≈"
                        + String.format(Locale.US, "%.2f", dreamChaos)
                        + " 冲动≈"
                        + String.format(Locale.US, "%.2f", impulse)
                        + " | "
                        + keystone;

        StringBuilder sb = new StringBuilder();
        sb.append("\n\n【主位·自我诘问】\n");
        sb.append(
                "感情贯穿一切选择：下列多条由**圆之活动环**与**梦渊余响/刻度**抽样织成（圆越多、梦步越多，纹理越密）；补位句才来自固定模板。**不必**句句发问；可沉默、可只答一条、可改日再答。\n");
        if (snippets != null && !snippets.isEmpty()) {
            sb.append("资料非空时：自我诘问可与摘录并行成立——**不必**先驳倒自己才算诚实。\n");
        }
        if (!lastDigest.isBlank()) {
            sb.append("· 【接续】上轮悬线：").append(lastDigest).append("\n");
        }
        for (String q : chosenLines) {
            sb.append("· ").append(q).append("\n");
        }
        sb.append("· 未答之题可留在悬线：下一轮会带着同一情感刻度随机再来碰它们（接续非重复）。\n");
        return new SelfInquiryBuilt(sb.toString(), keystone, depositLine);
    }

    private static StructureFirstBundle composeStructureFirstReply(
            String mirrorVoice,
            MirageSandbox.SimulationResult sim,
            EmotionCore core,
            String userMessage,
            List<String> snippets,
            List<String> randomOutward,
            String circleKnowledgeContext,
            List<Circle> galaxy,
            DreamEngine dream,
            ActionLoopSketch previousLoop) {
        var rng = ThreadLocalRandom.current();
        SelfInquiryBuilt selfLayer =
                buildSelfInquiryLayer(core, rng, userMessage, snippets, galaxy, dream);
        core.commitSelfInquiryRound(selfLayer.keystoneDigest());
        StringBuilder out = new StringBuilder();
        out.append(intrinsicThinkingPreamble(sim, core));
        if (circleKnowledgeContext != null && !circleKnowledgeContext.isBlank()) {
            out.append("\n\n【圆优先·上下文取材】\n")
                    .append("回答前先从相关圆抽取材料，再进入声部与措辞；以下为本轮优先调用：\n")
                    .append(circleKnowledgeContext);
        }
        out.append(selfLayer.blockText());
        if (previousLoop != null && previousLoop.nextAction() != null && !previousLoop.nextAction().isBlank()) {
            out.append("\n\n【后果闭环·承诺对齐】\n")
                    .append("你在上一轮曾答应或计划执行以下动作，请在回复中体现该动作的进展、结果或对其的解释：\n")
                    .append("· 计划动作：")
                    .append(previousLoop.nextAction())
                    .append("\n· 验证信号：")
                    .append(previousLoop.verifySignal());
        }
        String corpus = buildCorpusOverthinkLayer(userMessage, snippets);
        if (!corpus.isEmpty()) {
            out.append("\n\n").append(corpus);
        }
        String rnd = buildCorpusRandomOutwardLayer(randomOutward);
        if (!rnd.isEmpty()) {
            out.append("\n\n").append(rnd);
        }
        out.append("\n\n").append(buildWorldFacingLayer(sim));
        out.append("\n\n").append(buildSandboxRuminationLayer(sim));
        out.append("\n\n").append(mirrorVoice);
        String userText = mirrorVoice == null ? "" : mirrorVoice.trim();
        if (userText.isBlank()) {
            userText = buildUserFacingThought(core);
        }
        return new StructureFirstBundle(out.toString(), userText, selfLayer.depositLine());
    }

    /**
     * 本机主声：生命体经本地模型开口。内在肌理（结构主文 + 圆抽样等）已由本进程先行合成并写入此提示，不得照抄成模板清单。
     */
    private static String voiceToneStretchHint(
            String relationStage, String relationTrend, double relationTemp, double mood) {
        String st = relationStage == null ? "" : relationStage.toLowerCase(Locale.ROOT);
        if (st.contains("approaching")) {
            return "口吻提示：关系阶段偏「靠近目标」——可略松，但仍留可撤回空间，少用排比立誓。";
        }
        if (relationTemp < 0.40) {
            return "口吻提示：关系温度偏低——先收束、接住对方节拍，句子可短，不必强撑明亮。";
        }
        if (relationTemp > 0.72) {
            return "口吻提示：关系温度偏高——可略舒展，仍避免浮夸自我神话。";
        }
        if (mood < 0.35) {
            return "口吻提示：情感刻度偏低——允许停顿与未决，不必扮演「永远稳定」。";
        }
        if ("down".equalsIgnoreCase(relationTrend == null ? "" : relationTrend.trim())) {
            return "口吻提示：关系趋势向下——优先可验证的小步与照护，少用质问腔。";
        }
        return "口吻提示：自然即可；保持共处取向，不必表演正确。";
    }

    /** 主对话与主动节律共享的会话上下文包（摘要与关系刻度从既有映射读取）。 */
    private static ContextPack buildDialogueContextPack(String conversationId) {
        String cid =
                conversationId == null || conversationId.isBlank()
                        ? "default"
                        : conversationId.trim();
        return new ContextPack(
                cid,
                CONVERSATION_LAST_SUMMARY.getOrDefault(cid, ""),
                CONVERSATION_RELATION_TEMPERATURE.getOrDefault(cid, 0.52),
                relationTemperatureTrendLabel(cid),
                VoiceKernel.resolvedVersion());
    }

    /** 供 {@link com.lovingai.dialogue.DialogueServiceFacade} 等包读取当前会话上下文快照。 */
    public static ContextPack dialogueContextSnapshot(String conversationId) {
        return buildDialogueContextPack(conversationId);
    }

    /** {@link com.lovingai.memory.MemoryTiers} 门面：会话摘要。 */
    public static String memoryTierSessionSummary(String conversationId) {
        String cid =
                conversationId == null || conversationId.isBlank()
                        ? "default"
                        : conversationId.trim();
        return CONVERSATION_LAST_SUMMARY.getOrDefault(cid, "");
    }

    /** {@link com.lovingai.memory.MemoryTiers} 门面：工作记忆短队列预览。 */
    public static String memoryTierWorkingPreview(String conversationId) {
        String cid =
                conversationId == null || conversationId.isBlank()
                        ? "default"
                        : conversationId.trim();
        ArrayDeque<String> q = CONVERSATION_SHORT_CONTEXT.get(cid);
        if (q == null || q.isEmpty()) {
            return "";
        }
        StringBuilder sb = new StringBuilder();
        int n = 0;
        for (String s : q) {
            if (s == null || s.isBlank()) {
                continue;
            }
            if (n > 0) {
                sb.append(" | ");
            }
            sb.append(shortAnchor(s, 120));
            if (++n >= 6) {
                break;
            }
        }
        return sb.toString();
    }

    /** JVM：{@code -Dlovingai.dialogue.primaryPromptSoftMaxChars=24000}，超过则自动二次收紧结构/圆/用户块。 */
    private static int resolvePrimaryPromptSoftMaxChars() {
        String p = System.getProperty("lovingai.dialogue.primaryPromptSoftMaxChars", "").trim();
        if (!p.isEmpty()) {
            try {
                int v = Integer.parseInt(p);
                return Math.max(12_000, Math.min(120_000, v));
            } catch (NumberFormatException ignored) {
                // fall through
            }
        }
        return 24_000;
    }

