    private static String resolveOfflineAutonomyMode() {
        String raw = System.getProperty("lovingai.offlineAutonomy.mode", "deep");
        if (raw == null || raw.isBlank()) {
            return "deep";
        }
        String m = raw.trim().toLowerCase(Locale.ROOT);
        if ("light".equals(m) || "standard".equals(m) || "deep".equals(m)) {
            return m;
        }
        return "deep";
    }

    private static String readRequestBodySmall(com.sun.net.httpserver.HttpExchange exchange) throws IOException {
        try (InputStream is = exchange.getRequestBody()) {
            byte[] b = is.readNBytes(65537);
            if (b.length > 65536) {
                return "";
            }
            return new String(b, StandardCharsets.UTF_8);
        }
    }

    private static byte[] readRequestBodyBytes(com.sun.net.httpserver.HttpExchange exchange, int maxBytes)
            throws IOException {
        try (InputStream is = exchange.getRequestBody()) {
            byte[] b = is.readNBytes(maxBytes + 1);
            if (b.length > maxBytes) {
                throw new IOException("请求体过大");
            }
            return b;
        }
    }

