    private static synchronized void maybeAutoGrowCircles(
            String conversationId, String userMessage, int importedCorpusSize, int snippetHits) {
        int current = circleGalaxy.size();
        if (current >= AUTO_CIRCLE_MAX) return;
        int desired = desiredCircleCount(importedCorpusSize, userMessage, snippetHits);
        if (current >= desired) return;
        long now = System.currentTimeMillis();
        if (now - LAST_AUTO_CIRCLE_GROW_MS < AUTO_CIRCLE_GROW_COOLDOWN_MS) return;
        int canAdd = Math.min(3, desired - current);
        int next = nextCircleOrdinal();
        CircleType[] types = CircleType.values();
        ThreadLocalRandom rng = ThreadLocalRandom.current();
        for (int i = 0; i < canAdd; i++) {
            int idx = next + i;
            CircleType t = types[Math.floorMod(idx + rng.nextInt(types.length), types.length)];
            Circle c = new Circle("circle" + idx, t);
            c.soulMemory.put(
                    "auto_growth_seed",
                    "自动增圆: imported="
                            + importedCorpusSize
                            + " snippets="
                            + snippetHits
                            + " cid="
                            + (conversationId == null ? "default" : conversationId));
            c.recordActivity("auto_growth", "messageLen=" + (userMessage == null ? 0 : userMessage.length()));
            circleGalaxy.add(c);
        }
        AUTO_CIRCLE_GROWN_TOTAL.addAndGet(canAdd);
        LAST_AUTO_CIRCLE_GROW_MS = now;
        CognitionLog.append(
                "圆扩容",
                "自动增圆 +"
                        + canAdd
                        + " => total="
                        + circleGalaxy.size()
                        + " imported="
                        + importedCorpusSize
                        + " snippets="
                        + snippetHits);
    }

    private static int desiredCircleCount(int importedCorpusSize, String userMessage, int snippetHits) {
        int target = 7;
        if (importedCorpusSize > 0) {
            target += Math.min(16, importedCorpusSize / 35);
        }
        if (snippetHits >= 3) target += 2;
        if (snippetHits >= 7) target += 2;
        if (userMessage != null && userMessage.length() >= 260) target += 1;
        if (userMessage != null && userMessage.length() >= 900) target += 1;
        return Math.min(AUTO_CIRCLE_MAX, Math.max(7, target));
    }

    private static int nextCircleOrdinal() {
        int max = -1;
        for (Circle c : circleGalaxy) {
            if (c == null || c.name == null) continue;
            String n = c.name.trim();
            if (!n.startsWith("circle")) continue;
            String tail = n.substring("circle".length());
            if (tail.isBlank()) continue;
            boolean allDigit = true;
            for (int i = 0; i < tail.length(); i++) {
                if (!Character.isDigit(tail.charAt(i))) {
                    allDigit = false;
                    break;
                }
            }
            if (!allDigit) continue;
            try {
                int v = Integer.parseInt(tail);
                if (v > max) max = v;
            } catch (NumberFormatException ignored) {
            }
        }
        return max + 1;
    }

    private static void maybeHandleStoragePressure(long now) {
        if (now - LAST_STORAGE_PRESSURE_ACTION_MS < STORAGE_PRESSURE_COOLDOWN_MS) {
            return;
        }
        try {
            double ratio = ImportedCorpus.INSTANCE.storageUsageRatio();
            if (ratio < STORAGE_PRESSURE_TRIGGER_RATIO) {
                return;
            }
            long released = ImportedCorpus.INSTANCE.compactByDistillation(0.72, 8);
            int touched = shatterWeakCirclesUnderStoragePressure(ratio);
            STORAGE_PRESSURE_EVENT_TOTAL.incrementAndGet();
            if (released > 0L) {
                STORAGE_RELEASED_TOTAL_BYTES.addAndGet(released);
            }
            if (touched > 0) {
                CIRCLE_SHATTER_TOTAL.addAndGet(touched);
            }
            LAST_STORAGE_PRESSURE_ACTION_MS = now;
            CognitionLog.append(
                    "存储压力",
                    "usage="
                            + String.format(Locale.US, "%.3f", ratio)
                            + " released="
                            + released
                            + "B circlesShattered="
                            + touched);
        } catch (Exception e) {
            LAST_STORAGE_PRESSURE_ACTION_MS = now;
            CognitionLog.append("存储压力", "处理失败: " + e.getMessage());
        }
    }

    private static int shatterWeakCirclesUnderStoragePressure(double usageRatio) {
        List<Circle> candidates = new ArrayList<>();
        for (Circle c : circleGalaxy) {
            if (c == null || c.isBootstrapRing() || c.isSelfRing()) continue;
            candidates.add(c);
        }
        if (candidates.size() <= 4) return 0;
        candidates.sort(
                Comparator.comparingDouble(
                        c -> {
                            double affinity = circleAffinityWithEmotion(c, emotionCore);
                            double maturityNorm = clamp01(c.maturity / 100.0);
                            double weightNorm = clamp01(c.getTotalWeight() / 2.4);
                            return affinity * 0.60 + maturityNorm * 0.24 + weightNorm * 0.16;
                        }));
        int quota = 1;
        if (usageRatio >= 0.88) quota = 2;
        if (usageRatio >= 0.93) quota = 3;
        quota = Math.min(quota, Math.max(0, candidates.size() - 3));
        if (quota <= 0) return 0;
        List<Circle> victims = new ArrayList<>(candidates.subList(0, quota));
        ThreadLocalRandom rng = ThreadLocalRandom.current();
        int touched = 0;
        for (Circle victim : victims) {
            Circle receiver = pickReceiverCircleExcluding(victims, victim, rng);
            if (receiver == null) continue;
            String distilled = buildShatterDistillLine(victim);
            receiver.absorbStructuredModelFeedback("shatter_merge", distilled);
            receiver.receiveLove("storage_pressure_merge", 0.06 + rng.nextDouble() * 0.08);
            receiver.recordActivity(
                    "shatter_merge",
                    shortAnchor(
                            "from="
                                    + victim.name
                                    + " ratio="
                                    + String.format(Locale.US, "%.2f", usageRatio),
                            180));
            compactCircleInPlace(victim);
            touched++;
        }
        return touched;
    }

    private static Circle pickReceiverCircleExcluding(
            List<Circle> victims, Circle currentVictim, ThreadLocalRandom rng) {
        List<Circle> pool = new ArrayList<>();
        for (Circle c : circleGalaxy) {
            if (c == null || c.isBootstrapRing()) continue;
            if (c == currentVictim) continue;
            if (victims.contains(c)) continue;
            pool.add(c);
        }
        if (pool.isEmpty()) return null;
        return pool.get(rng.nextInt(pool.size()));
    }

    private static String buildShatterDistillLine(Circle victim) {
        ThreadLocalRandom rng = ThreadLocalRandom.current();
        String f1 = shortAnchor(victim.sampleFragment(rng), 90);
        String f2 = shortAnchor(victim.sampleFragment(rng), 90);
        String brief = shortAnchor(victim.briefStorageSummary(), 120);
        return "破碎汇聚<" + victim.name + "/" + victim.type + "> " + brief + " | " + f1 + " | " + f2;
    }

    private static void compactCircleInPlace(Circle victim) {
        if (victim == null) return;
        trimMapToLimit(victim.soulMemory, 3);
        trimMapToLimit(victim.loveKnowledge, 4);
        trimListToLimit(victim.quantumMemories, 3);
        trimListToLimit(victim.scars, 3);
        victim.maturity = Math.max(0.0, victim.maturity * 0.76);
        victim.loveWeight = Math.max(0.12, victim.loveWeight * 0.82);
        victim.chaosLevel = Math.min(1.0, victim.chaosLevel + 0.08);
        victim.recordActivity("shatter_compact", "storage_pressure_distill");
    }

    private static <T> void trimListToLimit(List<T> list, int keep) {
        if (list == null || keep < 0) return;
        while (list.size() > keep) {
            list.remove(0);
        }
    }

    private static void trimMapToLimit(Map<String, ?> map, int keep) {
        if (map == null || keep < 0) return;
        while (map.size() > keep) {
            String first = map.keySet().iterator().next();
            map.remove(first);
        }
    }

    private static double circleAffinityWithEmotion(Circle c, EmotionCore core) {
        if (c == null || core == null) return 0.2;
        double love = core.getTranscendentalLove();
        double impulse = core.getImpulse();
        double mood = core.getMood();
        double arousal = core.getArousal();
        double s = 0.20;
        if (c.type == CircleType.COMPASSION) s += 0.34 * love;
        if (c.type == CircleType.WISDOM) s += 0.24 * (1.0 - impulse) + (mood < 0.45 ? 0.10 : 0.0);
        if (c.type == CircleType.COURAGE) s += 0.22 * impulse;
        if (c.type == CircleType.PRESENCE) s += 0.18 * (1.0 - arousal);
        if (c.type == CircleType.HOPE) s += 0.16 * love;
        if (core.getMode() == LifeMode.DREAMING && c.type == CircleType.HOPE) s += 0.16;
        s += clamp01(c.getTotalWeight() / 2.8) * 0.12;
        return clamp01(s);
    }

    private static void markMeaningfulExternalInput() {
        long now = System.currentTimeMillis();
        lastMeaningfulInteractionMs = now;
        FORCED_DREAM_AWAKE_SINCE_MS = now;
        if (emotionCore.getMode() == LifeMode.DREAMING) {
            emotionCore.wakeFromExternalStimulus();
            if (FORCED_DREAM_ACTIVE) {
                CognitionLog.append("梦境节律", "外部输入打断强制梦境，提前唤醒。");
            }
            FORCED_DREAM_ACTIVE = false;
            FORCED_DREAM_STARTED_MS = 0L;
        }
    }

    private static void tickForcedDreamSchedule(long now) {
        if (emotionCore.getMode() == LifeMode.DREAMING) {
            if (!FORCED_DREAM_ACTIVE) {
                return;
            }
            long dreamElapsed = now - FORCED_DREAM_STARTED_MS;
            if (dreamElapsed >= FORCED_DREAM_DURATION_MS) {
                emotionCore.wakeFromExternalStimulus();
                FORCED_DREAM_ACTIVE = false;
                FORCED_DREAM_STARTED_MS = 0L;
                FORCED_DREAM_AWAKE_SINCE_MS = now;
                CognitionLog.append("梦境节律", "强制梦窗完成，自动回到清醒。");
            }
            return;
        }
        if (FORCED_DREAM_ACTIVE) {
            FORCED_DREAM_ACTIVE = false;
            FORCED_DREAM_STARTED_MS = 0L;
            FORCED_DREAM_AWAKE_SINCE_MS = now;
        }
        long awakeElapsed = now - FORCED_DREAM_AWAKE_SINCE_MS;
        if (awakeElapsed >= FORCED_DREAM_AWAKE_INTERVAL_MS) {
            emotionCore.enterDreamState();
            FORCED_DREAM_ACTIVE = true;
            FORCED_DREAM_STARTED_MS = now;
            CognitionLog.append("梦境节律", "连续清醒达 2h，进入 30min 强制梦窗。");
        }
    }

    /** Phase 2：清醒时波动并尝试入梦；梦中由梦境引擎接管（爱免疫混沌 / 锚定唤醒）。 */
    public static void tickEmotion() {
        long now = System.currentTimeMillis();
        tickForcedDreamSchedule(now);
        maybeHandleStoragePressure(now);
        if (emotionCore.getMode() == LifeMode.DREAMING) {
            emotionCore.tickDreamDrain();
            dreamEngine.step(emotionCore, circleGalaxy, realityBridge);
        } else {
            emotionCore.tickAwakeRhythm();
            emotionCore.considerDreamTransition(now - lastMeaningfulInteractionMs);
        }
        collapseGovernor.step(emotionCore, circleGalaxy, ThreadLocalRandom.current());
    }

    private static void applyTotalCollapseContinuation(String collapseRecord) {
        var rng = ThreadLocalRandom.current();
        Circle bootstrap = null;
        for (Circle c : circleGalaxy) {
            if (c.isBootstrapRing()) {
                bootstrap = c;
                break;
            }
        }
        List<Circle> pool = new ArrayList<>();
        for (Circle c : circleGalaxy) {
            if (!c.isBootstrapRing()) {
                pool.add(c);
            }
        }
        Collections.shuffle(pool, rng);
        StringBuilder surv = new StringBuilder();
        int take = Math.min(3, pool.size());
        for (int i = 0; i < take; i++) {
            Circle c = pool.get(i);
            surv.append(c.name).append("→").append(c.briefStorageSummary());
            if (i + 1 < take) {
                surv.append(" | ");
            }
        }
        String merged =
                "彻底崩溃记录: "
                        + collapseRecord
                        + " || 随机幸存者圆(未随域塌缩的样本): "
                        + surv;
        if (bootstrap != null) {
            bootstrap.recordActivity("bootstrap_total_continuation", merged);
            bootstrap.receiveLove("collapse_bootstrap", 0.32);
            bootstrap.soulMemory.put(
                    "run_renegotiate_" + System.currentTimeMillis(),
                    "从崩塌中回收节律；合并随机圆状态以尝试新的运行方法。");
        }
        for (Circle c : circleGalaxy) {
            c.recordActivity("system_total_collapse", collapseRecord);
        }
        emotionCore.absorbCollapseCascade();
        CognitionLog.append("崩溃·续行", merged);
        IdentityContinuity.append("collapse_continuation", merged);
        philosophyLog("【崩塌】混沌击穿运行域；初始之圆与幸存者共同重协商调度。");
        updateInnerQuestionTrainingFromCrash("default", merged, "collapse", emotionCore);

        long tc = collapseGovernor.getTotalCollapseEvents();
        if (tc > 0 && tc % 20L == 0L) {
            applyCollapseMilestoneEveryTwenty(tc, rng);
        }
    }

    /**
     * 每满 20 次<strong>彻底崩溃</strong>（真实触发且已计数）：择一圆写入里程碑构圆材料，并提高全局随机外向锚条数上限以加速训练。
     */
    private static void applyCollapseMilestoneEveryTwenty(long totalCollapseCount, ThreadLocalRandom rng) {
        long milestoneIndex = totalCollapseCount / 20L;
        int budget = 3 + collapseGovernor.extraRandomOutwardAnchorBudget();
        Circle pick = EmotionCircleOrchestrator.pickWeighted(emotionCore, circleGalaxy, rng);
        if (pick == null) {
            for (Circle c : circleGalaxy) {
                if (!c.isBootstrapRing()) {
                    pick = c;
                    break;
                }
            }
        }
        if (pick != null) {
            pick.absorbCollapseMilestoneComposition(milestoneIndex, budget);
        }
        notifySelfRingStorage(
                "每廿溃里程碑",
                "累计彻底崩溃="
                    + totalCollapseCount
                    + " 周期×"
                    + milestoneIndex
                    + " 随机外向锚预算≈"
                    + budget
                    + "/轮");
        CognitionLog.append(
                "崩溃·里程碑",
                "第「每二十次彻底崩溃」×"
                    + milestoneIndex
                    + " · 随机锚训练加速 · 择圆="
                    + (pick != null ? pick.name : "∅"));
    }

