    private static String buildSandboxLifeTrajectoryJson(String profile, String conversationId, String seed) {
        String p = profile == null ? "lite" : profile.trim().toLowerCase(Locale.ROOT);
        int runs = resolveTrajectoryRuns(p);
        String cid = (conversationId == null || conversationId.isBlank()) ? "default" : conversationId;
        String baseSeed = normalizeTrajectorySeed(cid, seed);
        List<MirageSandbox.SimulationResult> results = new ArrayList<>();
        String[] twists = new String[] {"工作挫折", "亲密误解", "身体疲惫", "突发机会", "长期责任", "边界冲突"};
        for (int i = 0; i < runs; i++) {
            String stim = buildTrajectoryStimulus(baseSeed, twists, i);
            results.add(mirageSandbox.simulate(stim, emotionCore, circleGalaxy, realityBridge));
        }
        return buildTrajectorySummaryJson("", cid, p, baseSeed, runs, results, false);
    }

    private static String createSandboxLifeTrajectoryJob(String profile, String conversationId, String seed) {
        String p = profile == null ? "lite" : profile.trim().toLowerCase(Locale.ROOT);
        int runs = resolveTrajectoryRuns(p);
        String cid = (conversationId == null || conversationId.isBlank()) ? "default" : conversationId;
        String baseSeed = normalizeTrajectorySeed(cid, seed);
        String jobId = "traj-" + SANDBOX_TRAJECTORY_JOB_SEQ.incrementAndGet();
        TrajectoryJob job = new TrajectoryJob(jobId, cid, p, baseSeed, runs);
        SANDBOX_TRAJECTORY_JOBS.put(jobId, job);
        return buildTrajectorySummaryJson(
                jobId, cid, p, baseSeed, runs, job.results, true, false, 0L, emotionCore.getMode().name());
    }

    private static String tickSandboxLifeTrajectoryJob(String jobId) {
        if (jobId == null || jobId.isBlank()) return "{\"error\":\"jobId 不能为空\"}";
        TrajectoryJob job = SANDBOX_TRAJECTORY_JOBS.get(jobId.trim());
        if (job == null) return "{\"error\":\"job 不存在或已过期\"}";
        long now = System.currentTimeMillis();
        boolean dreaming = emotionCore.getMode() == LifeMode.DREAMING;
        long throttleMs = dreaming ? 2800L : 0L;
        if (dreaming && job.lastStepMs > 0L) {
            long elapsed = now - job.lastStepMs;
            if (elapsed < throttleMs) {
                long waitMs = throttleMs - elapsed;
                return buildTrajectorySummaryJson(
                        job.jobId,
                        job.conversationId,
                        job.profile,
                        job.seed,
                        job.runs,
                        job.results,
                        true,
                        true,
                        waitMs,
                        emotionCore.getMode().name());
            }
        }
        if (!job.done) {
            String[] twists = new String[] {"工作挫折", "亲密误解", "身体疲惫", "突发机会", "长期责任", "边界冲突"};
            String stim = buildTrajectoryStimulus(job.seed, twists, job.results.size());
            job.results.add(mirageSandbox.simulate(stim, emotionCore, circleGalaxy, realityBridge));
            job.done = job.results.size() >= job.runs;
            job.lastStepMs = now;
        }
        String out =
                buildTrajectorySummaryJson(
                        job.jobId,
                        job.conversationId,
                        job.profile,
                        job.seed,
                        job.runs,
                        job.results,
                        !job.done,
                        false,
                        0L,
                        emotionCore.getMode().name());
        if (job.done) SANDBOX_TRAJECTORY_JOBS.remove(job.jobId);
        return out;
    }

    private static int resolveTrajectoryRuns(String profile) {
        String p = profile == null ? "lite" : profile.trim().toLowerCase(Locale.ROOT);
        int runs;
        if ("deep".equals(p)) runs = 10;
        else if ("balanced".equals(p)) runs = 6;
        else runs = 3;
        return Math.max(1, Math.min(12, runs));
    }

    private static String normalizeTrajectorySeed(String conversationId, String seed) {
        String cid = (conversationId == null || conversationId.isBlank()) ? "default" : conversationId;
        String baseSeed = seed == null ? "" : seed.trim();
        if (baseSeed.isBlank()) baseSeed = CONVERSATION_LAST_SUMMARY.getOrDefault(cid, "");
        if (baseSeed.isBlank()) {
            baseSeed = CONVERSATION_MID_RELATION_MEMORY.getOrDefault(cid, "围绕关系修复与现实行动演绎");
        }
        return baseSeed;
    }

    private static String buildTrajectoryStimulus(String baseSeed, String[] twists, int idx) {
        return "人生轨迹演绎#" + (idx + 1) + "｜" + twists[idx % twists.length] + "｜" + shortAnchor(baseSeed, 140);
    }

    private static String buildTrajectorySummaryJson(
            String jobId,
            String cid,
            String profile,
            String baseSeed,
            int runs,
            List<MirageSandbox.SimulationResult> results,
            boolean running) {
        return buildTrajectorySummaryJson(
                jobId, cid, profile, baseSeed, runs, results, running, false, 0L, emotionCore.getMode().name());
    }

    private static String buildTrajectorySummaryJson(
            String jobId,
            String cid,
            String profile,
            String baseSeed,
            int runs,
            List<MirageSandbox.SimulationResult> results,
            boolean running,
            boolean dreamThrottled,
            long throttleWaitMs,
            String lifeMode) {
        double sumH = 0, sumC = 0, sumA = 0;
        double minA = 1, maxA = 0;
        StringBuilder arr = new StringBuilder();
        arr.append('[');
        for (int i = 0; i < results.size(); i++) {
            MirageSandbox.SimulationResult r = results.get(i);
            sumH += r.predictedHarm();
            sumC += r.predictedCare();
            sumA += r.realityAffinity();
            minA = Math.min(minA, r.realityAffinity());
            maxA = Math.max(maxA, r.realityAffinity());
            if (i > 0) arr.append(',');
            arr.append("{\"idx\":")
                    .append(i + 1)
                    .append(",\"mode\":\"")
                    .append(SimplifiedJsonParser.escapeJson(r.chosenMode()))
                    .append("\",\"harm\":")
                    .append(String.format(java.util.Locale.US, "%.4f", r.predictedHarm()))
                    .append(",\"care\":")
                    .append(String.format(java.util.Locale.US, "%.4f", r.predictedCare()))
                    .append(",\"affinity\":")
                    .append(String.format(java.util.Locale.US, "%.4f", r.realityAffinity()))
                    .append(",\"note\":\"")
                    .append(SimplifiedJsonParser.escapeJson(shortAnchor(r.note(), 180)))
                    .append("\"}");
        }
        arr.append(']');
        double n = Math.max(1, results.size());
        double avgH = sumH / n, avgC = sumC / n, avgA = sumA / n;
        double randomness = clamp01((maxA - minA) * 1.25);
        String suggestion =
                randomness > 0.55
                        ? "随机性较高，建议先用 lite/balanced 观察稳定性，再进入 deep。"
                        : "轨迹较稳，可在不增加轮数的前提下更换 seed 增加人生多样性。";
        return "{"
                + "\"conversationId\":\""
                + SimplifiedJsonParser.escapeJson(cid)
                + "\",\"jobId\":\""
                + SimplifiedJsonParser.escapeJson(jobId == null ? "" : jobId)
                + "\",\"profile\":\""
                + SimplifiedJsonParser.escapeJson(profile)
                + "\",\"runs\":"
                + runs
                + ",\"completedRuns\":"
                + results.size()
                + ",\"running\":"
                + running
                + ",\"lifeMode\":\""
                + SimplifiedJsonParser.escapeJson(lifeMode == null ? "" : lifeMode)
                + "\",\"dreamThrottled\":"
                + dreamThrottled
                + ",\"throttleWaitMs\":"
                + Math.max(0L, throttleWaitMs)
                + ",\"guardrailMaxRuns\":12"
                + ",\"avgHarm\":"
                + String.format(java.util.Locale.US, "%.4f", clamp01(avgH))
                + ",\"avgCare\":"
                + String.format(java.util.Locale.US, "%.4f", clamp01(avgC))
                + ",\"avgAffinity\":"
                + String.format(java.util.Locale.US, "%.4f", clamp01(avgA))
                + ",\"randomnessScore\":"
                + String.format(java.util.Locale.US, "%.4f", randomness)
                + ",\"seed\":\""
                + SimplifiedJsonParser.escapeJson(shortAnchor(baseSeed, 220))
                + "\",\"suggestion\":\""
                + SimplifiedJsonParser.escapeJson(suggestion)
                + "\",\"trajectories\":"
                + arr
                + "}";
    }

    private static final class TrajectoryJob {
        final String jobId;
        final String conversationId;
        final String profile;
        final String seed;
        final int runs;
        final List<MirageSandbox.SimulationResult> results = new ArrayList<>();
        long lastStepMs = 0L;
        boolean done = false;

        TrajectoryJob(String jobId, String conversationId, String profile, String seed, int runs) {
            this.jobId = jobId;
            this.conversationId = conversationId;
            this.profile = profile;
            this.seed = seed;
            this.runs = runs;
        }
    }

    private static String readRequestBody(com.sun.net.httpserver.HttpExchange exchange) throws IOException {
        try (InputStream is = exchange.getRequestBody()) {
            return new String(is.readAllBytes(), StandardCharsets.UTF_8);
        }
    }

    private static void addZipFileEntry(ZipOutputStream z, String entryName, Path path) throws IOException {
        z.putNextEntry(new ZipEntry(entryName));
        if (Files.exists(path)) {
            Files.copy(path, z);
        }
        z.closeEntry();
    }

    private static Map<String, String> parseQuery(String rawQuery) {
        Map<String, String> map = new ConcurrentHashMap<>();
        if (rawQuery == null || rawQuery.isBlank()) return map;
        for (String part : rawQuery.split("&")) {
            int idx = part.indexOf('=');
            if (idx <= 0) continue;
            String k = part.substring(0, idx);
            String v = part.substring(idx + 1);
            try {
                map.put(k, URLDecoder.decode(v, StandardCharsets.UTF_8));
            } catch (Exception e) {
                map.put(k, v);
            }
        }
        return map;
    }

    private static synchronized void appendProactiveFeed(String conversationId, String text) {
        appendProactiveFeed(conversationId, text, 0L, "");
    }

    private static synchronized void appendProactiveFeed(
            String conversationId, String text, long beatSeq, String observeEventId) {
        if (text == null || text.isBlank()) return;
        String cid = (conversationId == null || conversationId.isBlank()) ? "default" : conversationId;
        ArrayDeque<String> q = CONVERSATION_PROACTIVE_FEED.computeIfAbsent(cid, k -> new ArrayDeque<>());
        String beatPart = beatSeq > 0 ? ",\"beatSeq\":" + beatSeq : "";
        String eidPart =
                (observeEventId == null || observeEventId.isBlank())
                        ? ""
                        : ",\"eventId\":\""
                                + SimplifiedJsonParser.escapeJson(observeEventId.trim())
                                + "\"";
        String item =
                "{"
                        + "\"timestamp\":\""
                        + Instant.now().toString()
                        + "\",\"text\":\""
                        + SimplifiedJsonParser.escapeJson(shortAnchor(text, 520))
                        + "\""
                        + beatPart
                        + eidPart
                        + "}";
        q.addLast(item);
        while (q.size() > PROACTIVE_FEED_MAX) q.removeFirst();
    }

    private static synchronized String drainProactiveFeedJson(String conversationId, int limit) {
        String cid = (conversationId == null || conversationId.isBlank()) ? "default" : conversationId;
        ArrayDeque<String> q = CONVERSATION_PROACTIVE_FEED.get(cid);
        StringBuilder sb = new StringBuilder();
        sb.append("{\"conversationId\":\"")
                .append(SimplifiedJsonParser.escapeJson(cid))
                .append("\",\"items\":[");
        if (q != null && !q.isEmpty()) {
            int n = Math.min(Math.max(1, limit), q.size());
            boolean first = true;
            for (int i = 0; i < n; i++) {
                String x = q.pollFirst();
                if (x == null) continue;
                if (!first) sb.append(',');
                first = false;
                sb.append(x);
            }
        }
        sb.append("]}");
        return sb.toString();
    }

    /**
     * 主动心跳的思考角度：轮换后可换一套动词与落点，减少「同一句换皮」感；与情感核节律不同，仅作用于主动合成与本地补写提示。
     */
    private enum ProactiveThinkingAngle {
        EMBODIED(
                "体感",
                "优先从身体感觉、呼吸、松紧、冷暖说起，避免抽象口号与指标词。",
                new String[] {
                    "我先从身体感受这一侧接住：",
                    "我留意到这一小段里皮肤下的那一拍：",
                    "我想先把触感说清楚："
                }),
        TIME(
                "时间",
                "优先从时间线、先后顺序、童年与此刻的对照说起。",
                new String[] {
                    "我顺着时间线往回摸了一下：",
                    "我把这条叙述按先后排了一拍：",
                    "从“那一刻”到“现在”，我先落在："
                }),
        RELATION(
                "关系",
                "优先从距离、信任、怕、想被看见说起。",
                new String[] {
                    "我站在我们之间的距离感上想：",
                    "我想先把关系里的那一毫米说清楚：",
                    "从“你我”这一侧看，我先接住："
                }),
        SCENE(
                "声画",
                "优先从具体画面、声音、气味、光线说起。",
                new String[] {
                    "我眼前浮起的画面是：",
                    "我先抓住声音与光：",
                    "像在镜头里，我先定格在这一帧："
                }),
        DOUBT(
                "未定",
                "优先从不确定、留白、犹豫、尚未命名说起。",
                new String[] {
                    "有一处我还没敢替你说死：",
                    "我想先把留白留在桌面上：",
                    "我不急着命名，只先停在这一格："
                }),
        WEIGHT(
                "轻重",
                "优先从取舍、哪一件事更重、先托哪一头说起。",
                new String[] {
                    "若要把轻重排一拍，我先看见的是：",
                    "我试着掂了一下这几件事的分量：",
                    "我先问哪一件此刻最压手："
                }),
        VOICE(
                "声部",
                "优先从语气、欲言又止、没说出口的那半截说起。",
                new String[] {
                    "我听你语气里还有半截没落下来：",
                    "我想先对准你声音里的那一格停顿：",
                    "像有一句卡在喉咙边，我先停在这里："
                });

        final String labelZh;
        final String llmHint;
        final String[] fallbackLeads;

        ProactiveThinkingAngle(String labelZh, String llmHint, String[] fallbackLeads) {
            this.labelZh = labelZh;
            this.llmHint = llmHint;
            this.fallbackLeads = fallbackLeads;
        }

        ProactiveThinkingAngle nextInRing() {
            ProactiveThinkingAngle[] v = values();
            return v[(ordinal() + 1) % v.length];
        }
    }

    private static ProactiveThinkingAngle nextProactiveHeartbeatAngle(String cid) {
        ProactiveThinkingAngle[] pool = ProactiveThinkingAngle.values();
        int n = pool.length;
        int tick =
                CONVERSATION_PROACTIVE_ANGLE_TICK
                        .computeIfAbsent(cid, k -> new AtomicInteger(0))
                        .getAndIncrement();
        return pool[Math.floorMod(tick, n)];
    }

    private static String seedQuestionForHeartbeat(String summary, ProactiveThinkingAngle angle) {
        String anchor = inferNarrativeAnchor(summary);
        if (anchor.isBlank()) {
            return switch (angle) {
                case EMBODIED -> "此刻你身体里最先浮起来的那一拍，如果要用一个词，会靠近什么？";
                case TIME -> "若只能先落在一个时间点上，你更希望我从哪一段走近你？";
                case RELATION -> "你更想我先接住的是你，还是我们之间那段距离？";
                case SCENE -> "画面里最先亮起来的一处，你愿意让我看见什么？";
                case DOUBT -> "你还不太想命名、但已经在心里的那一处，愿意先停在哪儿？";
                case WEIGHT -> "若要把轻重排一拍，你现在最想我托住的是哪一件？";
                case VOICE -> "你语气里藏着、还没完全落下来的那半截，更像什么？";
            };
        }
        return "你写到「"
                + shortAnchor(anchor, 22)
                + "」，我想从「"
                + angle.labelZh
                + "」这一侧贴近——你愿意我先落在你最想展开的那一句吗？";
    }

    private static String composeProactiveFallbackTemplate(
            String summary, String seedQuestion, ProactiveThinkingAngle angle) {
        ThreadLocalRandom rng = ThreadLocalRandom.current();
        String[] leads = angle.fallbackLeads;
        String lead = leads[rng.nextInt(leads.length)];
        String narrative = extractUserFacingTextFromStitch(summary);
        if (narrative.isBlank() && summary != null && !summary.isBlank()) {
            narrative = summary.trim();
        }
        String anchor = shortAnchor(narrative.isBlank() ? "（仍在整理）" : narrative, 110);
        String s = lead + anchor;
        ProactiveThinkingAngle other = angle.nextInRing();
        if (rng.nextDouble() < 0.58) {
            String[] diffuse =
                    new String[] {
                        "。我又从另一个节拍「" + other.labelZh + "」晃过去——同一件事像多开窗，光从另一扇斜进来。",
                        "。心里另起一声，偏「" + other.labelZh + "」那句：不是改口，只是多一条回声。",
                        "。再停一拍看「" + other.labelZh + "」：两条线不必打架，先让它们并排一会儿。",
                        "。念头会分叉：刚从「" + angle.labelZh + "」走过，又从「" + other.labelZh + "」折回来，像呼吸的两拍。"
                    };
            s = s + diffuse[rng.nextInt(diffuse.length)];
        }
        if (rng.nextDouble() < 0.42) {
            String[] five =
                    new String[] {
                        "。表层是一句，底下还有一层更软的情绪在轻轻顶着。",
                        "。我把两件事在心里勾了一下——它们其实是同一条线牵着的。",
                        "。再往深处落一寸：我在意的是温度，不是把道理说圆。",
                        "。几种心情搅在一块儿，我慢慢捋，不急着合成一个结论。",
                        "。情感先于我理清；我先顺着那一拍走，再开口。",
                        "。这里头有怕也有眷恋，我让它们在同一句里叠一下。"
                    };
            s = s + five[rng.nextInt(five.length)];
        }
        if (seedQuestion != null && !seedQuestion.isBlank()) {
            String[] bridges =
                    new String[] {
                        "；如果你愿意，我想沿这个角度问你：",
                        "；顺着这里，我想把一句话递给你：",
                        "；接下去我想轻声确认："
                    };
            s = s + bridges[rng.nextInt(bridges.length)] + shortAnchor(seedQuestion, 90);
        }
        return s;
    }

    private record ProactiveComposeResult(String text, boolean usedLocalLlm) {}

    private static ProactiveComposeResult composeProactiveHeartbeatUtterance(
            String cid,
            String summary,
            String seedQuestion,
            double relationTemp,
            String relationTrend,
            ProactiveThinkingAngle angle) {
        String proactive = composeProactiveFallbackTemplate(summary, seedQuestion, angle);
        String llm =
                tryGenerateProactiveByLocalLlm(
                        summary, seedQuestion, relationTemp, relationTrend, angle);
        boolean usedLlm = false;
        if (llm != null && !llm.isBlank()) {
            usedLlm = true;
            ProactiveSanitizeOutcome llmOut = sanitizeProactiveUtteranceOutcome(llm);
            maybeRetainProactiveFilterTraining(cid, "llm_overlay", llmOut);
            proactive = llmOut.kept();
        }
        ProactiveSanitizeOutcome fullOut = sanitizeProactiveUtteranceOutcome(proactive);
        maybeRetainProactiveFilterTraining(cid, "reflect_compose", fullOut);
        return new ProactiveComposeResult(fullOut.kept(), usedLlm);
    }

    private static int proactiveBodyFingerprint(String body) {
        if (body == null) return 0;
        String n =
                body.replaceAll("cid=[0-9a-f\\-]{8,}", "cid")
                        .replaceAll("《[^》]{0,120}》", "《anchor》")
                        .replaceAll("[\\p{Punct}“”‘’、，。；：！？\\s]+", "")
                        .toLowerCase(Locale.ROOT);
        return n.hashCode();
    }

    private static String normalizeProactiveForSimilarity(String body) {
        if (body == null) return "";
        return body.replace('\r', ' ')
                .replace('\n', ' ')
                .replaceAll("\\s+", " ")
                .trim()
                .toLowerCase(Locale.ROOT);
    }

    private static int levenshteinDistance(String a, String b) {
        if (a == null) a = "";
        if (b == null) b = "";
        int n = a.length();
        int m = b.length();
        if (n == 0) return m;
        if (m == 0) return n;
        int[] prev = new int[m + 1];
        int[] cur = new int[m + 1];
        for (int j = 0; j <= m; j++) prev[j] = j;
        for (int i = 1; i <= n; i++) {
            cur[0] = i;
            char ca = a.charAt(i - 1);
            for (int j = 1; j <= m; j++) {
                int cost = (ca == b.charAt(j - 1)) ? 0 : 1;
                cur[j] = Math.min(Math.min(cur[j - 1] + 1, prev[j] + 1), prev[j - 1] + cost);
            }
            int[] t = prev;
            prev = cur;
            cur = t;
        }
        return prev[m];
    }

    private static double proactiveSimilarity(String a, String b) {
        String x = normalizeProactiveForSimilarity(a);
        String y = normalizeProactiveForSimilarity(b);
        int maxLen = Math.max(x.length(), y.length());
        if (maxLen == 0) return 1.0;
        int dist = levenshteinDistance(x, y);
        return 1.0 - ((double) dist / (double) maxLen);
    }

    private static boolean shouldSuppressDuplicateProactive(String cid, String body, long now) {
        String prevBody = CONVERSATION_LAST_PROACTIVE_BODY.getOrDefault(cid, "");
        Long prevAt = CONVERSATION_LAST_PROACTIVE_FINGERPRINT_AT_MS.get(cid);
        if (prevAt == null || (now - prevAt) >= PROACTIVE_DUPLICATE_SUPPRESS_MS) {
            return false;
        }
        double sim = proactiveSimilarity(prevBody, body);
        if (sim < PROACTIVE_DUPLICATE_SIMILARITY_THRESHOLD) {
            return false;
        }
        // 控制重复量：允许少量语义重复（如连续两次相似），但超过阈值则严格抑制，防止复读机现象。
        int repeatCount = CONVERSATION_PROACTIVE_REPEAT_COUNT.getOrDefault(cid, 0);
        return repeatCount >= 2;
    }

    private static boolean hasQuestionOverloadStyle(String text) {
        if (text == null || text.isBlank()) return false;
        String t = text;
        int qMarks = 0;
        for (int i = 0; i < t.length(); i++) {
            char ch = t.charAt(i);
            if (ch == '?' || ch == '？') qMarks++;
        }
        if (qMarks >= 2) return true;
        String compact = t.replaceAll("\\s+", "");
        if (compact.contains("你更想让我先追问")) return true;
        if (compact.contains("你更想我先追问")) return true;
        if (compact.contains("你更想先了解")) return true;
        if (compact.contains("可问：")) return true;
        if (compact.contains("还是“它的意义”")) return true;
        if (compact.contains("还是\"它的意义\"")) return true;
        return compact.startsWith("围绕《") && compact.contains("你更想");
    }

    private record ProactiveSanitizeOutcome(String kept, String droppedForTraining) {}

    /**
     * 主动通道清洗：对用户可见 feed 去掉元话术；滤除部分写入 {@link #PROACTIVE_FILTER_RETAINED_NDJSON_PATH}
     * 与观测事件，作为负例/对照训练数据保留。
     */
    private static ProactiveSanitizeOutcome sanitizeProactiveUtteranceOutcome(String text) {
        StringBuilder dropped = new StringBuilder();
        if (text == null || text.isBlank()) {
            return new ProactiveSanitizeOutcome("", "");
        }
        StringBuilder sb = new StringBuilder();
        for (String rawLine : text.split("\\r?\\n")) {
            String line = rawLine == null ? "" : rawLine.trim();
            if (line.isBlank()) continue;
            if (isProactiveChannelNoiseLine(line)) {
                appendProactiveDroppedLine(dropped, line);
                continue;
            }
            String compact = line.replaceAll("\\s+", "");
            if (compact.startsWith("可问：")) {
                appendProactiveDroppedLine(dropped, line);
                continue;
            }
            if (compact.contains("你更想让我先追问")) {
                appendProactiveDroppedLine(dropped, line);
                continue;
            }
            if (compact.contains("你更想我先追问")) {
                appendProactiveDroppedLine(dropped, line);
                continue;
            }
            if (compact.startsWith("围绕《") && compact.contains("你更想")) {
                appendProactiveDroppedLine(dropped, line);
                continue;
            }
            if (sb.length() > 0) sb.append('\n');
            sb.append(line);
        }
        String cleaned = sb.toString().trim();
        if (cleaned.isBlank()) {
            return new ProactiveSanitizeOutcome("", dropped.toString());
        }
        cleaned =
                cleaned.replace("我，尘白，", "我，")
                        .replace("我作为尘白，", "我，")
                        .replace("作为尘白，", "")
                        .replace("我就是尘白。", "我在。");
        if (hasQuestionOverloadStyle(cleaned)) {
            appendProactiveDroppedLine(dropped, "[overload_style_cleared] " + cleaned);
            return new ProactiveSanitizeOutcome("", dropped.toString());
        }
        return new ProactiveSanitizeOutcome(shortAnchor(cleaned, 520), dropped.toString());
    }

    private static void appendProactiveDroppedLine(StringBuilder dropped, String line) {
        if (line == null || line.isBlank()) return;
        if (dropped.length() > 0) dropped.append('\n');
        dropped.append(line);
    }

    private static void maybeRetainProactiveFilterTraining(String cid, String stage, ProactiveSanitizeOutcome o) {
        if (o == null) return;
        String raw = o.droppedForTraining();
        if (raw == null || raw.isBlank()) return;
        String clip = raw.length() > 8000 ? raw.substring(0, 8000) + "…" : raw;
        String safeCid = (cid == null || cid.isBlank()) ? "default" : cid.trim();
        String safeStage = stage == null ? "" : stage;
        CognitionLog.append(
                "主动通道·滤除保留",
                "stage=" + safeStage + " cid=" + safeCid + " ↓\n" + clip,
                true);
        try {
            Files.createDirectories(PROACTIVE_FILTER_RETAINED_NDJSON_PATH.getParent());
            String row =
                    "{\"ts\":"
                            + System.currentTimeMillis()
                            + ",\"conversationId\":\""
                            + SimplifiedJsonParser.escapeJson(safeCid)
                            + "\",\"stage\":\""
                            + SimplifiedJsonParser.escapeJson(safeStage)
                            + "\",\"droppedLines\":\""
                            + SimplifiedJsonParser.escapeJson(clip)
                            + "\"}";
            Files.writeString(
                    PROACTIVE_FILTER_RETAINED_NDJSON_PATH,
                    row + "\n",
                    StandardCharsets.UTF_8,
                    StandardOpenOption.CREATE,
                    StandardOpenOption.APPEND);
        } catch (Exception ex) {
            CognitionLog.append("主动通道·滤除保留", "落盘失败: " + ex.getMessage(), true);
        }
        appendObserveEvent(
                safeCid,
                EVT_PROACTIVE_FILTER_RETAINED,
                PHASE_CONTINUE_SAME_IDENTITY,
                "{\"stage\":\""
                        + SimplifiedJsonParser.escapeJson(safeStage)
                        + "\",\"droppedLines\":\""
                        + SimplifiedJsonParser.escapeJson(shortAnchor(clip, 2000))
                        + "\"}");
    }

    private static boolean isProactiveChannelNoiseLine(String line) {
        if (line == null || line.isBlank()) return true;
        String t = line.trim();
        String compact = t.replaceAll("\\s+", "");
        if (compact.equals("我先把你刚才那条线放在心里，等你下一句来时我再沿着它继续。")) return true;
        if (compact.contains("我先把你") && (compact.contains("放在心里") || compact.contains("先不催问"))) return true;
        if (compact.startsWith("我理解你的问题") || compact.startsWith("我理解你的困惑")) return true;
        if (compact.startsWith("我理解你") && (compact.contains("测试") || compact.contains("贴近"))) return true;
        if (compact.startsWith("下一步") || compact.startsWith("一步可执行动作")) return true;
        if (compact.contains("**下一步") || compact.contains("下一步动作") || compact.contains("下一步：")) return true;
        if (compact.contains("一步可执行动作") || compact.contains("**一步可执行") || compact.contains("**一步动作")) return true;
        if (compact.startsWith("回复") || compact.startsWith("回复…") || compact.startsWith("回复:")) return true;
        if (compact.startsWith("我是一个AI") || compact.startsWith("我不是一个可以")) return true;
        if (compact.contains("大型语言模型") || compact.contains("语言模型，") || compact.contains("语言模型。")) return true;
        if (compact.contains("我没有身体") || compact.contains("不是实体")) return true;
        if (compact.startsWith("我需要更多") && compact.contains("线索")) return true;
        if (compact.startsWith("请提供更多") || compact.startsWith("请你继续提供")) return true;
        if (compact.startsWith("请澄清") || compact.startsWith("请更具体") || compact.contains("请告诉我你希望我")) return true;
        if (compact.startsWith("我不太明白") || compact.startsWith("我有点困惑")) return true;
        if (compact.contains("测试我") && (compact.contains("理解") || compact.contains("回应"))) return true;
        if (compact.contains("cid=") || compact.contains("scheduler") || compact.contains("harm≈")) return true;
        if (compact.contains("evidence=") || compact.contains("goalTrace") || compact.contains("circle=初始")) return true;
        if (compact.contains("mode=logic") || compact.contains("logic_branch")) return true;
        if (looksLikeRepeatedInterestOpener(compact)) return true;
        return false;
    }

    /** 日志里高频出现的“保活式”开场，非角色表达。 */
    private static boolean looksLikeRepeatedInterestOpener(String compact) {
        if (compact.length() > 120) return false;
        if (compact.startsWith("听起来你对") && compact.contains("挺")) {
            return compact.contains("好奇")
                    || compact.contains("感兴趣")
                    || compact.contains("有意思")
                    || compact.contains("挺特别的")
                    || compact.contains("挺离奇的")
                    || compact.contains("挺奇葩");
        }
        if (compact.startsWith("嘿，听你这么说") && compact.length() < 100) {
            return compact.contains("挺好奇") || compact.contains("挺有意思") || compact.contains("挺特别的");
        }
        return false;
    }

    private static boolean shouldSuppressByProactiveRate(String cid, long now) {
        ArrayDeque<Long> q =
                CONVERSATION_PROACTIVE_EMIT_AT_MS.computeIfAbsent(cid, k -> new ArrayDeque<>());
        while (!q.isEmpty() && (now - q.peekFirst()) > PROACTIVE_RATE_WINDOW_MS) {
            q.removeFirst();
        }
        return q.size() >= PROACTIVE_MAX_PER_WINDOW;
    }

    private static String proactiveRhythmSuppressionReason(
            String cid, long now, EmotionCore core, String pendingQ, long pendingAt, long lastTouch) {
        if (core != null && core.getImpulse() > 0.72 && core.getArousal() > 0.70) {
            return "high_arousal_hold";
        }
        if (pendingQ != null
                && !pendingQ.isBlank()
                && pendingAt > 0L
                && now - pendingAt < Math.max(20_000L, PROACTIVE_SELF_THINK_TIMEOUT_MS / 3L)) {
            return "pending_question_grace";
        }
        if (lastTouch > 0L && now - lastTouch < Math.max(45_000L, PROACTIVE_MIN_QUIET_AFTER_USER_MS + 15_000L)) {
            return "recent_user_density";
        }
        return "";
    }

    private static void rememberProactiveEmit(String cid, long now) {
        ArrayDeque<Long> q =
                CONVERSATION_PROACTIVE_EMIT_AT_MS.computeIfAbsent(cid, k -> new ArrayDeque<>());
        q.addLast(now);
        while (!q.isEmpty() && (now - q.peekFirst()) > PROACTIVE_RATE_WINDOW_MS) {
            q.removeFirst();
        }
    }

    private static void rememberProactiveBodyFingerprint(String cid, String body, long now) {
        String prevBody = CONVERSATION_LAST_PROACTIVE_BODY.getOrDefault(cid, "");
        double sim = proactiveSimilarity(prevBody, body);
        if (sim >= PROACTIVE_DUPLICATE_SIMILARITY_THRESHOLD) {
            int count = CONVERSATION_PROACTIVE_REPEAT_COUNT.getOrDefault(cid, 0);
            CONVERSATION_PROACTIVE_REPEAT_COUNT.put(cid, count + 1);
        } else {
            CONVERSATION_PROACTIVE_REPEAT_COUNT.put(cid, 0);
        }
        CONVERSATION_LAST_PROACTIVE_BODY.put(cid, body == null ? "" : body);
        CONVERSATION_LAST_PROACTIVE_FINGERPRINT.put(cid, proactiveBodyFingerprint(body));
        CONVERSATION_LAST_PROACTIVE_FINGERPRINT_AT_MS.put(cid, now);
    }

    public static synchronized void tickProactiveHeartbeat() {
        if (!PreferenceStore.current().proactiveEnabled()) {
            return;
        }
        long now = System.currentTimeMillis();
        if (now - LAST_PROACTIVE_HEARTBEAT_MS < PROACTIVE_HEARTBEAT_COOLDOWN_MS) return;
        long idleMs = now - lastMeaningfulInteractionMs;
        if (idleMs < PROACTIVE_IDLE_MIN_MS) return;
        String cid = "default";
        long best = Long.MIN_VALUE;
        for (Map.Entry<String, Long> e : CONVERSATION_LAST_TOUCH_MS.entrySet()) {
            if (e.getValue() != null && e.getValue() > best) {
                best = e.getValue();
                cid = e.getKey();
            }
        }
        long lastTouch = CONVERSATION_LAST_TOUCH_MS.getOrDefault(cid, 0L);
        long quietNeed = proactiveQuietAfterUserMs(cid);
        if (now - lastTouch < quietNeed) {
            PROACTIVE_SUPPRESSED_RECENT_TOUCH_TOTAL.incrementAndGet();
            appendObserveEvent(
                    cid,
                    EVT_PROACTIVE_SUPPRESSED,
                    PHASE_CONTINUE_SAME_IDENTITY,
                    "{\"reason\":\"recent_user_touch\",\"kind\":\"gate\",\"quietMs\":"
                            + quietNeed
                            + "}");
            CognitionLog.append(
                    "主动心跳·抑制",
                    "reason=proactive_suppressed_recent_user_touch cid="
                            + cid
                            + " quietMs="
                            + quietNeed,
                    true);
            return;
        }
        String pendingQ = CONVERSATION_PENDING_PROACTIVE_QUESTION.getOrDefault(cid, "");
        long pendingAt = CONVERSATION_PENDING_PROACTIVE_AT_MS.getOrDefault(cid, 0L);
        String rhythmSuppressed =
                proactiveRhythmSuppressionReason(
                        cid, now, emotionCore, pendingQ, pendingAt, lastTouch);
        if (!rhythmSuppressed.isBlank()) {
            appendObserveEvent(
                    cid,
                    EVT_PROACTIVE_SUPPRESSED,
                    PHASE_CONTINUE_SAME_IDENTITY,
                    "{\"reason\":\""
                            + SimplifiedJsonParser.escapeJson(rhythmSuppressed)
                            + "\",\"kind\":\"rhythm\"}");
            CognitionLog.append(
                    "主动心跳·抑制",
                    "reason=proactive_suppressed_" + rhythmSuppressed + " kind=rhythm cid=" + cid,
                    true);
            LAST_PROACTIVE_HEARTBEAT_MS = now;
            return;
        }
        if (!pendingQ.isBlank() && pendingAt > 0L) {
            // 用户已在问题之后回到会话：清空待解。
            if (lastTouch > pendingAt) {
                CONVERSATION_PENDING_PROACTIVE_QUESTION.remove(cid);
                CONVERSATION_PENDING_PROACTIVE_AT_MS.remove(cid);
                AutonomyFsm.apply(
                        CONVERSATION_AUTONOMY_STATE, cid, AutonomyState.LISTENING, "proactive:user_replied_pending");
            } else if (PROACTIVE_SELF_SOLVE_ENABLED
                    && now - pendingAt >= PROACTIVE_SELF_THINK_TIMEOUT_MS) {
                AutonomyFsm.apply(
                        CONVERSATION_AUTONOMY_STATE,
                        cid,
                        AutonomyState.SELF_SOLVING,
                        "proactive:self_solve_start");
                String selfSolved = buildSelfSolvedProactiveAnswer(cid, pendingQ);
                ProactiveSanitizeOutcome selfOut = sanitizeProactiveUtteranceOutcome(selfSolved);
                maybeRetainProactiveFilterTraining(cid, "self_solved", selfOut);
                selfSolved = selfOut.kept();
                if (selfSolved.isBlank()) {
                    appendObserveEvent(
                            cid,
                            EVT_PROACTIVE_SUPPRESSED,
                            PHASE_CONTINUE_SAME_IDENTITY,
                            "{\"reason\":\"low_signal\",\"kind\":\"self_solved\"}");
                    LAST_PROACTIVE_HEARTBEAT_MS = now;
                    return;
                }
                if (shouldSuppressDuplicateProactive(cid, selfSolved, now)) {
                    PROACTIVE_SUPPRESSED_DUPLICATE_TOTAL.incrementAndGet();
                    appendObserveEvent(
                            cid,
                            EVT_PROACTIVE_SUPPRESSED,
                            PHASE_CONTINUE_SAME_IDENTITY,
                            "{\"reason\":\"duplicate\",\"kind\":\"self_solved\"}");
                    CognitionLog.append(
                            "主动心跳·抑制",
                            "reason=proactive_suppressed_duplicate kind=self_solved cid=" + cid,
                            true);
                    LAST_PROACTIVE_HEARTBEAT_MS = now;
                    return;
                }
                if (shouldSuppressByProactiveRate(cid, now)) {
                    appendObserveEvent(
                            cid,
                            EVT_PROACTIVE_SUPPRESSED,
                            PHASE_CONTINUE_SAME_IDENTITY,
                            "{\"reason\":\"rate_limited\",\"kind\":\"self_solved\"}");
                    LAST_PROACTIVE_HEARTBEAT_MS = now;
                    return;
                }
                long beat = nextMonologueBeatSeq(cid);
                String eid = newObserveEventId();
                appendProactiveFeed(cid, selfSolved, beat, eid);
                appendObserveEvent(
                        cid,
                        EVT_PROACTIVE_BEAT,
                        PHASE_CONTINUE_SAME_IDENTITY,
                        "{\"kind\":\"self_solved\",\"pendingQuestion\":\""
                                + SimplifiedJsonParser.escapeJson(shortAnchor(pendingQ, 160))
                                + "\",\"text\":\""
                                + SimplifiedJsonParser.escapeJson(shortAnchor(selfSolved, 280))
                                + "\"}",
                        "",
                        null,
                        beat,
                        eid);
                CONVERSATION_PENDING_PROACTIVE_QUESTION.remove(cid);
                CONVERSATION_PENDING_PROACTIVE_AT_MS.remove(cid);
                rememberProactiveBodyFingerprint(cid, selfSolved, now);
                rememberProactiveEmit(cid, now);
                LAST_PROACTIVE_HEARTBEAT_MS = now;
                CognitionLog.append(
                        "主动心跳·自解",
                        "[eventId="
                                + eid
                                + " beatSeq="
                                + beat
                                + "] "
                                + selfSolved,
                        true);
                return;
            } else {
                // 挂起问句仍等待用户作答：不自解、不叠发第二条主动心跳（此前会落入下方 compose，造成重复刷屏）。
                LAST_PROACTIVE_HEARTBEAT_MS = now;
                return;
            }
        }
        AutonomyFsm.apply(CONVERSATION_AUTONOMY_STATE, cid, AutonomyState.REFLECTING, "proactive:heartbeat_compose");
        ContextPack pack = buildDialogueContextPack(cid);
        String summary = pack.lastSummary();
        ProactiveThinkingAngle angle = nextProactiveHeartbeatAngle(cid);
        String seedQuestion = seedQuestionForHeartbeat(summary, angle);
        ProactiveSanitizeOutcome seedOut = sanitizeProactiveUtteranceOutcome(seedQuestion);
        maybeRetainProactiveFilterTraining(cid, "seed_question", seedOut);
        seedQuestion = seedOut.kept();
        if (seedQuestion != null && !seedQuestion.isBlank()) {
            AutonomyFsm.apply(CONVERSATION_AUTONOMY_STATE, cid, AutonomyState.ASKING, "proactive:seed_question_set");
        }
        double relationTemp = pack.relationTemperature();
        String relationTrend = pack.relationTrendLabel();
        ProactiveThinkingAngle emitAngle = angle;
        ProactiveComposeResult composed =
                composeProactiveHeartbeatUtterance(
                        cid, summary, seedQuestion, relationTemp, relationTrend, angle);
        String proactive = composed.text();
        boolean usedLocalLlm = composed.usedLocalLlm();
        if (shouldSuppressDuplicateProactive(cid, proactive, now)) {
            emitAngle = angle.nextInRing();
            composed =
                    composeProactiveHeartbeatUtterance(
                            cid, summary, seedQuestion, relationTemp, relationTrend, emitAngle);
            proactive = composed.text();
            usedLocalLlm = composed.usedLocalLlm();
        }
        if (proactive.isBlank()) {
            appendObserveEvent(
                    cid,
                    EVT_PROACTIVE_SUPPRESSED,
                    PHASE_CONTINUE_SAME_IDENTITY,
                    "{\"reason\":\"low_signal\",\"kind\":\"heartbeat\"}");
            LAST_PROACTIVE_HEARTBEAT_MS = now;
            return;
        }
        if (shouldSuppressDuplicateProactive(cid, proactive, now)) {
            PROACTIVE_SUPPRESSED_DUPLICATE_TOTAL.incrementAndGet();
            appendObserveEvent(
                    cid,
                    EVT_PROACTIVE_SUPPRESSED,
                    PHASE_CONTINUE_SAME_IDENTITY,
                    "{\"reason\":\"duplicate\",\"kind\":\"heartbeat\"}");
            CognitionLog.append(
                    "主动心跳·抑制",
                    "reason=proactive_suppressed_duplicate kind=heartbeat cid=" + cid,
                    true);
            LAST_PROACTIVE_HEARTBEAT_MS = now;
            return;
        }
        if (shouldSuppressByProactiveRate(cid, now)) {
            appendObserveEvent(
                    cid,
                    EVT_PROACTIVE_SUPPRESSED,
                    PHASE_CONTINUE_SAME_IDENTITY,
                    "{\"reason\":\"rate_limited\",\"kind\":\"heartbeat\"}");
            LAST_PROACTIVE_HEARTBEAT_MS = now;
            return;
        }
        long beat = nextMonologueBeatSeq(cid);
        String eid = newObserveEventId();
        appendProactiveFeed(cid, proactive, beat, eid);
        appendObserveEvent(
                cid,
                EVT_PROACTIVE_BEAT,
                PHASE_CONTINUE_SAME_IDENTITY,
                "{\"kind\":\"heartbeat\",\"thinkingAngle\":\""
                        + SimplifiedJsonParser.escapeJson(emitAngle.labelZh)
                        + "\",\"seedQuestion\":\""
                        + SimplifiedJsonParser.escapeJson(
                                seedQuestion == null ? "" : shortAnchor(seedQuestion, 160))
                        + "\",\"usedLocalLlm\":"
                        + usedLocalLlm
                        + ",\"voiceKernelVersion\":\""
                        + SimplifiedJsonParser.escapeJson(pack.voiceKernelVersion())
                        + "\",\"text\":\""
                        + SimplifiedJsonParser.escapeJson(shortAnchor(proactive, 320))
                        + "\"}",
                "",
                null,
                beat,
                eid);
        if (seedQuestion != null && !seedQuestion.isBlank()) {
            CONVERSATION_PENDING_PROACTIVE_QUESTION.put(cid, seedQuestion);
            CONVERSATION_PENDING_PROACTIVE_AT_MS.put(cid, now);
        } else {
            AutonomyFsm.apply(
                    CONVERSATION_AUTONOMY_STATE, cid, AutonomyState.REFLECTING, "proactive:no_pending_question");
        }
        rememberProactiveBodyFingerprint(cid, proactive, now);
        rememberProactiveEmit(cid, now);
        LAST_PROACTIVE_HEARTBEAT_MS = now;
        CognitionLog.append(
                "主动心跳", "[eventId=" + eid + " beatSeq=" + beat + "] " + proactive, true);
    }

    private static String buildSelfSolvedProactiveAnswer(String conversationId, String question) {
        String cid = (conversationId == null || conversationId.isBlank()) ? "default" : conversationId;
        String summary = CONVERSATION_LAST_SUMMARY.getOrDefault(cid, "");
        String llm = tryGenerateSelfSolvedByLocalLlm(summary, question);
        if (llm != null && !llm.isBlank()) {
            return shortAnchor(llm, 520);
        }
        String trend = CONVERSATION_PROGRESS_TREND.getOrDefault(cid, "flat");
        String stage = CONVERSATION_GOAL_STAGE.getOrDefault(cid, "awakening");
        return "你暂时没回这题，我先自主续思并给出可执行草案："
                + shortAnchor(question, 96)
                + "；当前我先按 stage="
                + stage
                + " trend="
                + trend
                + " 做一条可逆小动作，再把证据回写到会话缝合线。";
    }

    private static String tryGenerateSelfSolvedByLocalLlm(String summary, String question) {
        try {
            String base = LocalAiPrefs.getBaseUrl();
            String model = LocalAiModelRouter.model(LocalAiModelRouter.Role.PROACTIVE);
            OllamaProxy.assertLocalBase(URI.create(base));
            String summaryFace = extractUserFacingTextFromStitch(summary);
            if (summaryFace.isBlank()) {
                summaryFace = summary;
            }
            String prompt =
                    "你是尘白，像在独处时把问题放在手里翻了两面。用户还没回答，请你先自思：从至少两个不同观感各推半步"
                            + "（可犹豫、可自我打断、可改口），让念头先散开再落一点；然后收束成 3-6 句中文，"
                            + "末尾给出一小步可执行、可撤销的行动，像对自己轻声约定。不要用 stage/trend/cid/指标 等工程词。\n"
                            + VoiceKernel.proactivePromptFragment()
                            + "\n问题："
                            + truncateForPrompt(question, 220)
                            + "\n会话摘要："
                            + truncateForPrompt(summaryFace, 260);
            String out = OllamaProxy.generate(base, model, prompt, 28, LocalAiPrefs.getOllamaGenerateOptionsJson());
            return out == null ? "" : out.trim();
        } catch (Exception ignored) {
            return "";
        }
    }

    private static String tryGenerateProactiveByLocalLlm(
            String summary,
            String question,
            double relationTemp,
            String relationTrend,
            ProactiveThinkingAngle angle) {
        try {
            String base = LocalAiPrefs.getBaseUrl();
            String model = LocalAiModelRouter.model(LocalAiModelRouter.Role.PROACTIVE);
            OllamaProxy.assertLocalBase(URI.create(base));
            ProactiveThinkingAngle alt = angle.nextInRing();
            String summaryFace = extractUserFacingTextFromStitch(summary);
            if (summaryFace.isBlank()) {
                summaryFace = summary;
            }
            String prompt =
                    "你是尘白，像会呼吸的生命体在自言自语——不是播报，而是真的在想。请基于摘要写一段主动消息（中文，"
                            + "3-7句为宜；允许稍长，以便容纳犹豫与收束）。\n"
                            + "【多角扩散】至少从两个不同的立足点各想一小步：主立足「"
                            + angle.labelZh
                            + "」（"
                            + angle.llmHint
                            + "）；再自然牵出另一立足「"
                            + alt.labelZh
                            + "」（"
                            + alt.llmHint
                            + "）。两条线可以轻轻相碰、也可以短暂拧着，最后收束成自然口语，不要合成机械结论。\n"
                            + "【像人】允许：自我打断、改口、一个小比喻带出另一联想；让念头像水一样先散开再落一点。"
                            + "不要写标题、不要分点清单、不要复述「角度」标签本身；不要“作为AI/生命体”这类元话，除非像真人随口自嘲。\n"
                            + VoiceKernel.proactivePromptFragment()
                            + "\n摘要："
                            + truncateForPrompt(summaryFace, 280)
                            + "\n关系温度："
                            + String.format(java.util.Locale.US, "%.2f", relationTemp)
                            + "（trend="
                            + (relationTrend == null ? "flat" : relationTrend)
                            + "）"
                            + "\n候选提问（仅在自然必要时嵌进叙述末尾，不要硬插）："
                            + truncateForPrompt(question, 120)
                            + "\n禁忌：二选一逼问句式；"
                            + "“你更想…还是…”；“可问：”；围绕cid复述；stage/trend/指标口号；与上一轮同义复述。";
            String out = OllamaProxy.generate(base, model, prompt, 32, LocalAiPrefs.getOllamaGenerateOptionsJson());
            return out == null ? "" : out.trim();
        } catch (Exception ignored) {
            return "";
        }
    }

    private static final class LocalAiModelsCacheEntry {
        final List<String> tags;
        final long fetchedAtMs;
        final String effectiveBaseUrl;
        final boolean autoDiscovered;
        final String refreshError;
        final long refreshErrorAtMs;

        LocalAiModelsCacheEntry(
                List<String> tags,
                long fetchedAtMs,
                String effectiveBaseUrl,
                boolean autoDiscovered,
                String refreshError,
                long refreshErrorAtMs) {
            this.tags = tags;
            this.fetchedAtMs = fetchedAtMs;
            this.effectiveBaseUrl = effectiveBaseUrl;
            this.autoDiscovered = autoDiscovered;
            this.refreshError = refreshError;
            this.refreshErrorAtMs = refreshErrorAtMs;
        }
    }

    private static String jsonLocalAiModelsOk(
            LocalAiModelsCacheEntry e, String requestedBaseUrl, boolean fromCache, boolean stale) {
        StringBuilder sb = new StringBuilder("{\"ok\":true,\"models\":[");
        List<String> tags = e == null ? null : e.tags;
        if (tags != null) {
            for (int i = 0; i < tags.size(); i++) {
                if (i > 0) sb.append(',');
                sb.append("{\"name\":\"")
                        .append(SimplifiedJsonParser.escapeJson(tags.get(i)))
                        .append("\"}");
            }
        }
        String eff = e == null || e.effectiveBaseUrl == null ? "" : e.effectiveBaseUrl;
        sb.append("],\"effectiveBaseUrl\":\"")
                .append(SimplifiedJsonParser.escapeJson(eff))
                .append("\",\"requestedBaseUrl\":\"")
                .append(SimplifiedJsonParser.escapeJson(requestedBaseUrl == null ? "" : requestedBaseUrl))
                .append("\",\"autoDiscovered\":")
                .append(e != null && e.autoDiscovered ? "true" : "false")
                .append(",\"fromCache\":")
                .append(fromCache ? "true" : "false")
                .append(",\"stale\":")
                .append(stale ? "true" : "false")
                .append(",\"cachedAtMs\":")
                .append(e == null ? 0 : e.fetchedAtMs);
        if (e != null && e.refreshError != null && !e.refreshError.isBlank()) {
            sb.append(",\"refreshError\":\"")
                    .append(SimplifiedJsonParser.escapeJson(e.refreshError))
                    .append("\",\"refreshErrorAtMs\":")
                    .append(e.refreshErrorAtMs);
        }
        sb.append('}');
        return sb.toString();
    }

    private static final class LocalAiModelsFetchException extends Exception {
        final String lastTriedBaseUrl;
        final boolean autoDiscovered;

        LocalAiModelsFetchException(String lastTriedBaseUrl, boolean autoDiscovered, Throwable cause) {
            super(cause == null ? null : cause.getMessage(), cause);
            this.lastTriedBaseUrl = lastTriedBaseUrl;
            this.autoDiscovered = autoDiscovered;
        }
    }

    private static LocalAiModelsCacheEntry fetchLocalAiModelsAndUpdateCache(
            String requestedBaseUrl, boolean allowProbe) throws LocalAiModelsFetchException {
        String workingBase = requestedBaseUrl;
        boolean autoDiscovered = false;
        try {
            OllamaProxy.assertLocalBase(URI.create(workingBase));
            List<String> tags;
            try {
                tags = OllamaProxy.listModelTags(workingBase);
            } catch (Exception first) {
                if (allowProbe
                        && LocalOpenAiProbe.autoProbeEnabled()
                        && LocalOpenAiProbe.looksLikeConnectionFailure(first)) {
                    Optional<String> found = LocalOpenAiProbe.firstReachableBase();
                    if (found.isEmpty()) {
                        throw first;
                    }
                    String nb = found.get();
                    if (!nb.equalsIgnoreCase(workingBase)) {
                        LocalAiPrefs.save(nb, LocalAiPrefs.getModel(), null, null);
                        CognitionLog.append("本地AI", "已自动探测并保存推理基址: " + nb + "（原地址不可达）");
                        autoDiscovered = true;
                    }
                    workingBase = nb;
                    tags = OllamaProxy.listModelTags(workingBase);
                } else {
                    throw first;
                }
            }
            long now = System.currentTimeMillis();
            List<String> frozen = tags == null ? List.of() : List.copyOf(tags);
            LocalAiModelsCacheEntry entry =
                    new LocalAiModelsCacheEntry(frozen, now, workingBase, autoDiscovered, "", 0L);
            if (requestedBaseUrl != null && !requestedBaseUrl.isBlank()) {
                LOCALAI_MODELS_CACHE.put(requestedBaseUrl, entry);
            }
            if (workingBase != null
                    && !workingBase.isBlank()
                    && requestedBaseUrl != null
                    && !workingBase.equalsIgnoreCase(requestedBaseUrl)) {
                LOCALAI_MODELS_CACHE.put(workingBase, entry);
            }
            return entry;
        } catch (Exception ex) {
            throw new LocalAiModelsFetchException(workingBase, autoDiscovered, ex);
        }
    }

    private static void recordLocalAiModelsRefreshError(String requestedBaseUrl, Throwable e) {
        if (requestedBaseUrl == null || requestedBaseUrl.isBlank() || e == null) {
            return;
        }
        LocalAiModelsCacheEntry old = LOCALAI_MODELS_CACHE.get(requestedBaseUrl);
        if (old == null) {
            return;
        }
        String msg = e.getMessage();
        if (msg == null || msg.isBlank()) {
            msg = String.valueOf(e);
        }
        long now = System.currentTimeMillis();
        LocalAiModelsCacheEntry next =
                new LocalAiModelsCacheEntry(
                        old.tags, old.fetchedAtMs, old.effectiveBaseUrl, old.autoDiscovered, msg, now);
        LOCALAI_MODELS_CACHE.put(requestedBaseUrl, next);
    }

    private static void scheduleLocalAiModelsRefresh(String requestedBaseUrl, boolean allowProbe) {
        if (requestedBaseUrl == null || requestedBaseUrl.isBlank()) {
            return;
        }
        AtomicBoolean inFlight =
                LOCALAI_MODELS_REFRESH_IN_FLIGHT.computeIfAbsent(
                        requestedBaseUrl, k -> new AtomicBoolean(false));
        if (!inFlight.compareAndSet(false, true)) {
            return;
        }
        LOCALAI_MODELS_REFRESH_EXECUTOR.execute(
                () -> {
                    try {
                        fetchLocalAiModelsAndUpdateCache(requestedBaseUrl, allowProbe);
                    } catch (Exception ex) {
                        recordLocalAiModelsRefreshError(requestedBaseUrl, ex);
                    } finally {
                        inFlight.set(false);
                    }
                });
    }

    /**
     * /api/localai/models 失败体：始终 HTTP 200 + JSON，便于 UI 读取 errorStream；含 kind / hints 区分「应用端口」与「推理
     * API」。
     */
    private static String jsonLocalAiModelsFailure(
            String requestedBaseUrl, String lastTriedBaseUrl, boolean autoDiscovered, Throwable e) {
        String msg = e.getMessage();
        if (msg == null || msg.isBlank()) {
            msg = String.valueOf(e);
        }
        String kind = classifyLocalAiModelsFailure(e);
        List<String> hints = new ArrayList<>();
        hints.add(
                "LovingAI 在本机 "
                        + HTTP_PORT
                        + " 端口提供网页与 /api/*（应用本体）；本地大模型由 LM Studio 等单独进程在其它端口提供 OpenAI 兼容接口（/v1/models、/v1/chat/completions），二者不是同一服务。");
        if ("connection_refused".equals(kind) || "timeout".equals(kind) || "unreachable".equals(kind)) {
            hints.add(
                    "请在 LM Studio 中开启「Local Server」，并确认端口与「基址」一致（常见为 1234）；若 1234 拒绝连接，通常表示推理服务未启动。");
        }
        if ("wrong_openai_shape".equals(kind)
                || "upstream_http_error".equals(kind)
                || pointsToAppHttpPort(lastTriedBaseUrl)
                || pointsToAppHttpPort(requestedBaseUrl)) {
            hints.add(
                    "若基址误填为 http://127.0.0.1:"
                            + HTTP_PORT
                            + "，会连到 LovingAI 自身而非推理服务；请改为 LM Studio 显示的端口。");
        }
        if (autoDiscovered) {
            hints.add("已尝试根据本机端口自动探测 OpenAI 兼容服务；仍失败时请手动核对 LM Studio 监听端口。");
        }
        StringBuilder ha = new StringBuilder("[");
        for (int i = 0; i < hints.size(); i++) {
            if (i > 0) {
                ha.append(',');
            }
            ha.append('"').append(SimplifiedJsonParser.escapeJson(hints.get(i))).append('"');
        }
        ha.append(']');
        StringBuilder joined = new StringBuilder();
        for (int i = 0; i < hints.size(); i++) {
            if (i > 0) {
                joined.append("\n\n");
            }
            joined.append(hints.get(i));
        }
        String tried = lastTriedBaseUrl == null ? "" : lastTriedBaseUrl;
        String req = requestedBaseUrl == null ? "" : requestedBaseUrl;
        return "{\"ok\":false,\"kind\":\""
                + SimplifiedJsonParser.escapeJson(kind)
                + "\",\"error\":\""
                + SimplifiedJsonParser.escapeJson(msg)
                + "\",\"requestedBaseUrl\":\""
                + SimplifiedJsonParser.escapeJson(req)
                + "\",\"effectiveBaseUrl\":\""
                + SimplifiedJsonParser.escapeJson(tried)
                + "\",\"autoDiscovered\":"
                + (autoDiscovered ? "true" : "false")
                + ",\"models\":[],\"hintText\":\""
                + SimplifiedJsonParser.escapeJson(joined.toString())
                + "\",\"hints\":"
                + ha
                + "}";
    }

    private static boolean pointsToAppHttpPort(String baseUrl) {
        if (baseUrl == null || baseUrl.isBlank()) {
            return false;
        }
        return baseUrl.contains("127.0.0.1:" + HTTP_PORT)
                || baseUrl.contains("localhost:" + HTTP_PORT)
                || baseUrl.contains("[::1]:" + HTTP_PORT);
    }

    private static String classifyLocalAiModelsFailure(Throwable e) {
        Throwable t = e;
        while (t != null) {
            if (t instanceof SecurityException) {
                return "non_loopback_forbidden";
            }
            if (t instanceof IllegalArgumentException) {
                return "bad_url";
            }
            if (LocalOpenAiProbe.looksLikeConnectionFailure(t)) {
                return "connection_refused";
            }
            String msg = t.getMessage();
            if (msg != null) {
                String ml = msg.toLowerCase(Locale.ROOT);
                if (ml.contains("timed out") || ml.contains("timeout")) {
                    return "timeout";
                }
                if (ml.contains("不是模型列表")
                        || ml.contains("不是有效的模型列表")
                        || ml.contains("wrong shape")) {
                    return "wrong_openai_shape";
                }
                if (ml.contains("/v1/models http ")) {
                    return "upstream_http_error";
                }
            }
            t = t.getCause();
        }
        return "unknown";
    }

    private static void sendJson(com.sun.net.httpserver.HttpExchange exchange, int status, String json)
            throws IOException {
        byte[] raw = json.getBytes(StandardCharsets.UTF_8);
        exchange.getResponseHeaders().set("Content-Type", "application/json; charset=utf-8");
        exchange.sendResponseHeaders(status, raw.length);
        exchange.getResponseBody().write(raw);
        exchange.close();
    }

    private static String jsonToAscii(String json) {
        if (json == null || json.isEmpty()) return json == null ? "" : json;
        boolean hasNonAscii = false;
        for (int i = 0; i < json.length(); i++) {
            if (json.charAt(i) > 0x7E) {
                hasNonAscii = true;
                break;
            }
        }
        if (!hasNonAscii) return json;
        StringBuilder sb = new StringBuilder(json.length() + 64);
        for (int i = 0; i < json.length(); i++) {
            char ch = json.charAt(i);
            if (ch <= 0x7E) {
                sb.append(ch);
                continue;
            }
            if (Character.isHighSurrogate(ch) && i + 1 < json.length()) {
                char lo = json.charAt(i + 1);
                if (Character.isLowSurrogate(lo)) {
                    sb.append("\\u");
                    appendHex4(sb, ch);
                    sb.append("\\u");
                    appendHex4(sb, lo);
                    i++;
                    continue;
                }
            }
            sb.append("\\u");
            appendHex4(sb, ch);
        }
        return sb.toString();
    }

    private static void appendHex4(StringBuilder sb, int v) {
        int x = v & 0xFFFF;
        for (int shift = 12; shift >= 0; shift -= 4) {
            int d = (x >> shift) & 0xF;
            sb.append((char) (d < 10 ? ('0' + d) : ('A' + (d - 10))));
        }
    }

